/// CR 122.1 + CR 608.2d: Bribe Taker building-block — "for each kind of
/// counter on permanents you control, you may put your choice of a +1/+1
/// counter or a counter of that kind on this creature" lifts a
/// `DistinctCounterKindsAmong` iteration source onto `repeat_for` and a
/// `ChooseOneOf` body with a fixed (+1/+1) branch and a dynamic
/// `RebindToIteratedKind` branch, both targeting `SelfRef`.
#[test]
fn bribe_taker_for_each_counter_kind_choice() {
    let mut ctx = ParseContext::default();
    let def = parse_effect_chain_with_context(
            "for each kind of counter on permanents you control, you may put your choice of a +1/+1 counter or a counter of that kind on ~.",
            AbilityKind::Spell,
            &mut ctx,
        );
    // CR 122.1: iteration source lifted onto the parent's repeat_for.
    match &def.repeat_for {
        Some(QuantityExpr::Ref {
            qty: QuantityRef::DistinctCounterKindsAmong { filter },
        }) => match filter {
            TargetFilter::Typed(tf) => {
                assert_eq!(tf.type_filters, vec![TypeFilter::Permanent]);
                assert_eq!(tf.controller, Some(ControllerRef::You));
            }
            other => panic!("expected typed permanent filter, got {other:?}"),
        },
        other => panic!("expected DistinctCounterKindsAmong repeat_for, got {other:?}"),
    }
    // CR 608.2: "you may" → optional choice.
    assert!(def.optional, "expected optional ChooseOneOf");
    match &*def.effect {
        Effect::ChooseOneOf { chooser, branches } => {
            assert_eq!(*chooser, PlayerFilter::Controller);
            assert_eq!(branches.len(), 2);
            // Fixed branch: +1/+1 on self, no kind binding.
            assert_eq!(branches[0].iteration_kind_binding, None);
            match &*branches[0].effect {
                Effect::PutCounter {
                    counter_type,
                    target,
                    ..
                } => {
                    assert_eq!(*counter_type, CounterType::Plus1Plus1);
                    assert_eq!(*target, TargetFilter::SelfRef);
                }
                other => panic!("expected PutCounter fixed branch, got {other:?}"),
            }
            // Dynamic branch: tagged RebindToIteratedKind, on self.
            assert_eq!(
                branches[1].iteration_kind_binding,
                Some(IterationKindBinding::RebindToIteratedKind)
            );
            match &*branches[1].effect {
                Effect::PutCounter { target, .. } => {
                    assert_eq!(*target, TargetFilter::SelfRef);
                }
                other => panic!("expected PutCounter dynamic branch, got {other:?}"),
            }
        }
        other => panic!("expected ChooseOneOf, got {other:?}"),
    }
}

/// Generality check: a non-+1/+1 fixed counter ("a lore counter or a counter
/// of that kind") proves the class is not hardcoded to +1/+1.
#[test]
fn for_each_counter_kind_choice_non_p1p1_fixed() {
    let mut ctx = ParseContext::default();
    let def = parse_effect_chain_with_context(
            "for each kind of counter on permanents you control, put your choice of a lore counter or a counter of that kind on ~.",
            AbilityKind::Spell,
            &mut ctx,
        );
    assert!(matches!(
        &def.repeat_for,
        Some(QuantityExpr::Ref {
            qty: QuantityRef::DistinctCounterKindsAmong { .. }
        })
    ));
    // No "you may" → mandatory.
    assert!(!def.optional);
    match &*def.effect {
        Effect::ChooseOneOf { branches, .. } => {
            match &*branches[0].effect {
                Effect::PutCounter { counter_type, .. } => {
                    assert_eq!(*counter_type, CounterType::Lore);
                }
                other => panic!("expected PutCounter, got {other:?}"),
            }
            assert_eq!(
                branches[1].iteration_kind_binding,
                Some(IterationKindBinding::RebindToIteratedKind)
            );
        }
        other => panic!("expected ChooseOneOf, got {other:?}"),
    }
}

/// CR 122.1 + CR 608.2d: targeted per-kind add-OR-remove choice — the
/// Dramatist's Puppet / Quarry Hauler class. "for each kind of counter on
/// target permanent, put another counter of that kind on it or remove one
/// from it" must lower to a `TargetOnly` parent (surfacing the "target
/// permanent" slot) plus a sub-ability carrying a `ChooseOneOf` add/remove
/// choice driven once per distinct kind on the chosen permanent — NOT
/// `Unimplemented`.
#[test]
fn for_each_counter_kind_adjust_target_choice() {
    let mut ctx = ParseContext::default();
    let def = parse_effect_chain_with_context(
            "for each kind of counter on target permanent, put another counter of that kind on it or remove one from it.",
            AbilityKind::Spell,
            &mut ctx,
        );

    // Parent: TargetOnly with a concrete (non-Any) target so a target slot
    // is requested.
    let target = match &*def.effect {
        Effect::TargetOnly { target } => {
            assert_ne!(
                *target,
                TargetFilter::Any,
                "TargetOnly must carry a concrete permanent filter so a target slot is built"
            );
            target.clone()
        }
        other => panic!("expected TargetOnly parent, got {other:?}"),
    };
    assert!(
        def.effect.target_filter().is_some(),
        "the clause must surface a target filter"
    );
    assert_eq!(target, def.effect.target_filter().cloned().unwrap());

    // Sub-ability: the per-kind choice driven by the DistinctCounterKindsAmong
    // loop over the chosen target (ParentTarget).
    let sub = def
        .sub_ability
        .as_ref()
        .expect("adjust-target clause must carry a choice sub-ability");
    match &sub.repeat_for {
        Some(QuantityExpr::Ref {
            qty: QuantityRef::DistinctCounterKindsAmong { filter },
        }) => assert_eq!(
            *filter,
            TargetFilter::ParentTarget,
            "iteration source must resolve against the chosen target"
        ),
        other => panic!("expected DistinctCounterKindsAmong repeat_for, got {other:?}"),
    }
    match &*sub.effect {
        Effect::ChooseOneOf { chooser, branches } => {
            assert_eq!(*chooser, PlayerFilter::Controller);
            assert_eq!(branches.len(), 2, "add and remove branches");
            // Both branches are dynamic (rebind to the iterated kind) and act
            // on the chosen permanent.
            let mut saw_add = false;
            let mut saw_remove = false;
            for branch in branches {
                assert_eq!(
                    branch.iteration_kind_binding,
                    Some(IterationKindBinding::RebindToIteratedKind),
                    "every branch must rebind to the iterated kind"
                );
                match &*branch.effect {
                    Effect::PutCounter { target, .. } => {
                        assert_eq!(*target, TargetFilter::ParentTarget);
                        saw_add = true;
                    }
                    Effect::RemoveCounter { target, count, .. } => {
                        assert_eq!(*target, TargetFilter::ParentTarget);
                        assert_eq!(
                            *count,
                            QuantityExpr::Fixed { value: 1 },
                            "remove exactly one counter of that kind"
                        );
                        saw_remove = true;
                    }
                    other => panic!("expected Put/RemoveCounter branch, got {other:?}"),
                }
            }
            assert!(saw_add && saw_remove, "both add and remove options present");
        }
        other => panic!("expected ChooseOneOf sub-effect, got {other:?}"),
    }
}

/// Word-order independence (build for the class): "remove one from it or put
/// another counter of that kind on it" parses to the same structure.
#[test]
fn for_each_counter_kind_adjust_target_remove_first_order() {
    let mut ctx = ParseContext::default();
    let def = parse_effect_chain_with_context(
            "for each kind of counter on target creature, remove one from it or put another counter of that kind on it.",
            AbilityKind::Spell,
            &mut ctx,
        );
    assert!(
        matches!(&*def.effect, Effect::TargetOnly { .. }),
        "reverse word order must still produce a TargetOnly clause, got {:?}",
        def.effect
    );
    let sub = def.sub_ability.as_ref().expect("choice sub-ability");
    assert!(matches!(
        &sub.repeat_for,
        Some(QuantityExpr::Ref {
            qty: QuantityRef::DistinctCounterKindsAmong { .. }
        })
    ));
    assert!(matches!(&*sub.effect, Effect::ChooseOneOf { .. }));
}

/// CR 603.2: the full Dramatist's Puppet / Quarry Hauler card — an
/// enters-the-battlefield trigger whose body is the targeted per-kind
/// add/remove choice. Confirms the trigger surfaces the body (not
/// Unimplemented) and the target rides on the trigger's execute body.
#[test]
fn dramatists_puppet_etb_targeted_counter_adjust() {
    let parsed = crate::parser::oracle::parse_oracle_text(
            "When this creature enters, for each kind of counter on target permanent, put another counter of that kind on it or remove one from it.",
            "Dramatist's Puppet",
            &[],
            &["Creature".to_string()],
            &[],
        );
    let trigger = parsed
        .triggers
        .first()
        .expect("should produce the enters trigger");
    let execute = trigger
        .execute
        .as_ref()
        .expect("trigger has an execute body");
    assert!(
        matches!(&*execute.effect, Effect::TargetOnly { .. }),
        "ETB trigger body must be the targeted counter-adjust TargetOnly clause, got {:?}",
        execute.effect
    );
    let sub = execute
        .sub_ability
        .as_ref()
        .expect("trigger body must carry the choice sub-ability");
    assert!(matches!(&*sub.effect, Effect::ChooseOneOf { .. }));
}

/// CR 608.2c (issue #503): "exile ~, then return him to the battlefield
/// transformed" — clause 2's bare pronoun "him" binds to the source named
/// by clause 1 (`exile ~` → SelfRef), NOT to the typed Cat trigger
/// subject. Building-block test: drives `parse_effect_chain_ir` directly.
#[test]
fn anaphor_rebinds_to_self_after_named_exile_clause() {
    let mut ctx = cat_subject_ctx();
    let def = parse_effect_chain_with_context(
            "you may exile ~, then return him to the battlefield transformed under his owner's control.",
            AbilityKind::Spell,
            &mut ctx,
        );
    // Clause 1: exile ~ → SelfRef.
    match &*def.effect {
        Effect::ChangeZone {
            destination: Zone::Exile,
            target: TargetFilter::SelfRef,
            ..
        } => {}
        other => panic!("expected clause 1 = ChangeZone exile SelfRef, got {other:?}"),
    }
    // Clause 2 (sub_ability): return him transformed → SelfRef, not
    // TriggeringSource.
    let sub = def.sub_ability.as_ref().expect("clause 2 sub_ability");
    match &*sub.effect {
        Effect::ChangeZone {
            destination: Zone::Battlefield,
            target,
            enter_transformed,
            ..
        } => {
            assert_eq!(
                *target,
                TargetFilter::SelfRef,
                "clause 2 pronoun 'him' must bind to SelfRef (Ajani), not the Cat subject"
            );
            assert!(*enter_transformed, "clause 2 must carry enter_transformed");
        }
        other => panic!("expected clause 2 = ChangeZone battlefield, got {other:?}"),
    }
}

/// CR 608.2c (issue #1354): a source object named inside a nested
/// sub-ability still establishes the referent for a later bare pronoun.
/// Coveted Jewel's trigger parses the first sentence as Draw →
/// GiveControl(SelfRef); the following "Untap it" must bind to that
/// artifact, not to the typed attacking-creature trigger subject.
#[test]
fn anaphor_rebinds_to_self_after_nested_give_control_clause() {
    let mut ctx = cat_subject_ctx();
    let def = parse_effect_chain_with_context(
        "you draw three cards and gain control of ~. Untap it.",
        AbilityKind::Spell,
        &mut ctx,
    );
    let give = def.sub_ability.as_ref().expect("give-control sub_ability");
    match &*give.effect {
        Effect::GiveControl {
            target: TargetFilter::SelfRef,
            ..
        } => {}
        Effect::GainControl {
            target: TargetFilter::SelfRef,
        } => {}
        other => panic!("expected source-object control effect, got {other:?}"),
    }
    let untap = give.sub_ability.as_ref().expect("untap sub_ability");
    match &*untap.effect {
        Effect::SetTapState {
            scope: EffectScope::Single,
            state: TapStateChange::Untap,
            target,
        } => assert_eq!(
            *target,
            TargetFilter::SelfRef,
            "trailing pronoun must bind to the named source object, not TriggeringSource",
        ),
        other => panic!("expected SetTapState(Untap), got {other:?}"),
    }
}

/// CR 608.2k (issue #319, negative guard): a bare-pronoun clause with NO
/// preceding `exile ~`/`SelfRef` clause must NOT be rewritten — "exile it"
/// under a typed Cat subject stays bound to the triggering source.
#[test]
fn anaphor_self_rewrite_does_not_fire_without_named_clause() {
    let mut ctx = cat_subject_ctx();
    let def = parse_effect_chain_with_context("exile it.", AbilityKind::Spell, &mut ctx);
    match &*def.effect {
        Effect::ChangeZone {
            destination: Zone::Exile,
            target,
            ..
        } => assert_eq!(
            *target,
            TargetFilter::TriggeringSource,
            "single-clause 'exile it' must stay TriggeringSource (issue #319 class)"
        ),
        other => panic!("expected ChangeZone exile, got {other:?}"),
    }
}

#[test]
fn counter_suffix_body_fixed_count_regression() {
    // Regression: the fixed-count path still parses after the dynamic arm
    // was prepended.
    let (rest, (counter, count)) =
        parse_counter_suffix_body_combinator("two +1/+1 counters on it").unwrap();
    assert_eq!(rest, "");
    assert_eq!(counter, crate::types::counter::CounterType::Plus1Plus1);
    assert_eq!(count, QuantityExpr::Fixed { value: 2 });
}

// CR 603.7e + CR 118.1: "choose any number of <filter> and pay <cost> for
// each <noun> chosen this way" → ChooseObjectsIntoTrackedSet → PayCost
// { ScaledMana { base, times: TrackedSetSize } }. Magnetic Mountain class.
#[test]
fn choose_and_pay_per_object_generic_cost() {
    let text = "that player may choose any number of tapped blue creatures \
                    they control and pay {4} for each creature chosen this way";
    let lower = text.to_lowercase();
    let mut ctx = ParseContext::default();
    let clause = try_parse_choose_and_pay_per_object(text, &lower, &mut ctx)
        .expect("Magnetic Mountain main clause must parse");
    // Head: ChooseObjectsIntoTrackedSet, chooser = TriggeringPlayer.
    let Effect::ChooseObjectsIntoTrackedSet {
        chooser, min, max, ..
    } = &clause.effect
    else {
        panic!(
            "expected ChooseObjectsIntoTrackedSet, got {:?}",
            clause.effect
        );
    };
    assert_eq!(*chooser, TargetFilter::TriggeringPlayer);
    assert_eq!(
        (*min, *max),
        (0, None),
        "\"any number of\" → min 0, max None"
    );
    assert!(
        clause.optional,
        "\"that player may\" makes the clause optional"
    );
    // sub_ability: PayCost { ScaledMana { base: {4}, times: TrackedSetSize } }.
    let pay = clause.sub_ability.as_ref().expect("PayCost sub_ability");
    let Effect::PayCost { cost, scale, payer } = pay.effect.as_ref() else {
        panic!("expected PayCost, got {:?}", pay.effect);
    };
    assert_eq!(*payer, TargetFilter::TriggeringPlayer);
    let AbilityCost::Mana { cost: base } = cost else {
        panic!("expected Mana base, got {cost:?}");
    };
    assert_eq!(*base, crate::types::mana::ManaCost::generic(4));
    assert_eq!(
        *scale,
        Some(QuantityExpr::Ref {
            qty: QuantityRef::TrackedSetSize
        })
    );
}

// CR 118.1: Colored-pip base ({U}) scales as a full ManaCost — the
// Thelon's Curse case the AbilityCost::ManaDynamic family cannot express.
#[test]
fn choose_and_pay_per_object_colored_pip_cost() {
    let text = "that player may choose any number of tapped blue creatures \
                    they control and pay {U} for each creature chosen this way";
    let lower = text.to_lowercase();
    let mut ctx = ParseContext::default();
    let clause = try_parse_choose_and_pay_per_object(text, &lower, &mut ctx)
        .expect("Thelon's Curse main clause must parse");
    let pay = clause.sub_ability.as_ref().expect("PayCost sub_ability");
    let Effect::PayCost {
        cost: AbilityCost::Mana { cost: base },
        scale: Some(_),
        ..
    } = pay.effect.as_ref()
    else {
        panic!("expected PayCost {{ Mana, scale }}, got {:?}", pay.effect);
    };
    assert_eq!(
        *base,
        crate::types::mana::ManaCost::Cost {
            shards: vec![crate::types::mana::ManaCostShard::Blue],
            generic: 0,
        },
        "colored pip {{U}} preserved as the scaled base"
    );
}

