fn assert_graveyard_card_count_condition(condition: &AbilityCondition, expected: TypeFilter) {
    let AbilityCondition::QuantityCheck {
        lhs:
            QuantityExpr::Ref {
                qty:
                    QuantityRef::ZoneCardCount {
                        zone,
                        card_types,
                        scope,
                        filter: None,
                    },
            },
        comparator: Comparator::GE,
        rhs: QuantityExpr::Fixed { value: 1 },
    } = condition
    else {
        panic!("expected graveyard card count condition, got {condition:?}");
    };
    assert_eq!(*zone, ZoneRef::Graveyard);
    assert_eq!(*scope, CountScope::Controller);
    assert_eq!(card_types, &vec![expected]);
}

/// CR 601.2f: Regression gate — "This ability costs {1} less to activate
/// for each page counter on this artifact" must parse into an
/// `Effect::Unimplemented` sub_ability whose description carries the full
/// cost-reduction sentence, so `strip_cost_reduction_node` can promote it
/// to `def.cost_reduction`. Previously the bare `"this "` subject-prefix
/// in `strip_subject_clause` caused the sentence to be misparsed as
/// `Effect::Counter { target: Any }` by finding the noun "counter" (in
/// "page counter") and mistaking it for the verb "counter" (as in
/// counter-a-spell). Reproduced on Diary of Dreams.
#[test]
fn diary_of_dreams_cost_reduction_not_misparsed_as_counterspell() {
    let def = parse_effect_chain(
            "Draw a card. This ability costs {1} less to activate for each page counter on this artifact.",
            AbilityKind::Activated,
        );
    // The effect chain itself must be Draw (no counterspell poisoning).
    assert!(
        matches!(&*def.effect, Effect::Draw { .. }),
        "expected Draw as primary effect, got {:?}",
        def.effect
    );
    // The cost-reduction sentence MUST reach `strip_cost_reduction_node`
    // as Unimplemented text. The sub_ability may be present (before
    // extraction) or absorbed into def.cost_reduction by the downstream
    // `extract_cost_reduction_from_chain` pass run from `oracle.rs`. Here
    // we only verify it's NOT a spurious Counter effect.
    if let Some(sub) = &def.sub_ability {
        assert!(
            !matches!(&*sub.effect, Effect::Counter { .. }),
            "sub_ability must not be a counter-spell effect, got {:?}",
            sub.effect
        );
    }
}

/// MSH-A C2 — Whiplash, Vengeful Engineer. After Fix A2, the where-X clause
/// "where X is the number of Equipment attached to him" binds BOTH the LoseLife
/// and GainLife amounts to a typed `ObjectCount{Equipment, AttachedToSource}`
/// (fail-before: `QuantityRef::Variable("the number of Equipment attached to
/// him")` string fallback). This is the in-scope win.
///
/// GATE (recorded, NOT met by parser-only A2+B1): the clean each-opponent form
/// Both the each-opponent form (`player_scope == Some(Opponent)`,
/// `LoseLife.target == None`) and the intervening-if `condition` are now
/// produced. The follow-up bridge maps `StaticCondition::SourceIsEquipped`
/// to `TriggerCondition::SourceMatchesFilter { HasAttachment(Equipment) }`
/// (oracle_trigger.rs `static_condition_to_trigger_condition`), so
/// `try_extract_intervening` succeeds, `strip_condition_clause` removes
/// "if he's equipped," and the body once again starts with "each opponent ",
/// letting `strip_each_player_subject` (lower.rs:2542) fire. This closed the
/// two previously recorded gaps.
#[test]
fn whiplash_where_x_binds_equipment_count_to_life_loss_and_gain() {
    use crate::parser::oracle_trigger::parse_trigger_line;
    let def = parse_trigger_line(
            "Whenever Whiplash attacks, if he's equipped, each opponent loses X life and you gain X life, where X is the number of Equipment attached to him.",
            "Whiplash, Vengeful Engineer",
        );
    let execute = def.execute.expect("attack execute");

    let expected_amount = QuantityExpr::Ref {
        qty: QuantityRef::ObjectCount {
            filter: TargetFilter::Typed(
                TypedFilter::default()
                    .subtype("Equipment".to_string())
                    .properties(vec![FilterProp::AttachedToSource]),
            ),
        },
    };
    // The in-scope A2 win: LoseLife amount is the typed ObjectCount, NOT Variable.
    match &*execute.effect {
        Effect::LoseLife { amount, target, .. } => {
            assert_eq!(
                amount, &expected_amount,
                "LoseLife amount must bind to typed ObjectCount(Equipment+AttachedToSource)"
            );
            // Each-opponent form: the life loss is player-scoped, not targeted.
            assert_eq!(
                target, &None,
                "each-opponent LoseLife must not carry a target (player_scope drives it)"
            );
            // Reinforce the discriminating property (AttachedToSource present).
            match amount {
                QuantityExpr::Ref {
                    qty:
                        QuantityRef::ObjectCount {
                            filter: TargetFilter::Typed(tf),
                        },
                } => assert!(
                    tf.properties.contains(&FilterProp::AttachedToSource),
                    "amount filter must carry AttachedToSource, got {:?}",
                    tf.properties
                ),
                other => panic!("expected ObjectCount amount, got {other:?}"),
            }
        }
        other => panic!("expected LoseLife, got {other:?}"),
    }
    // The sibling GainLife shares the same typed binding (CR 107.3i).
    let gain = execute.sub_ability.expect("gain_life sibling");
    match &*gain.effect {
        Effect::GainLife { amount, .. } => assert_eq!(
            amount, &expected_amount,
            "GainLife amount must share the typed ObjectCount binding"
        ),
        other => panic!("expected GainLife, got {other:?}"),
    }

    // Bridge follow-up (closed): the intervening-if condition is now carried
    // as SourceMatchesFilter{HasAttachment(Equipment)} (CR 603.4 + CR 301.5a),
    // and stripping it lets the each-opponent subject be recognized.
    match def.condition {
        Some(TriggerCondition::SourceMatchesFilter {
            filter: TargetFilter::Typed(ref tf),
        }) => assert!(
            tf.properties.iter().any(|p| matches!(
                p,
                FilterProp::HasAttachment {
                    kind: AttachmentKind::Equipment,
                    ..
                }
            )),
            "condition filter must carry HasAttachment(Equipment), got {:?}",
            tf.properties
        ),
        other => panic!("expected SourceMatchesFilter(HasAttachment Equipment), got {other:?}"),
    }
    assert_eq!(
        execute.player_scope,
        Some(PlayerFilter::Opponent),
        "each-opponent scope is now produced once the 'if he's equipped,' clause \
             is stripped, letting strip_each_player_subject fire"
    );
}

/// Issue #1424 — The Scarab God upkeep: opponent life loss and scry share
/// the zombie-count binding from the trailing where-X clause.
#[test]
fn scarab_god_upkeep_where_x_binds_zombie_count_to_life_loss_and_scry() {
    use crate::parser::oracle_trigger::parse_trigger_line;
    let def = parse_trigger_line(
            "At the beginning of your upkeep, each opponent loses X life and you scry X, where X is the number of Zombies you control.",
            "The Scarab God",
        );
    let execute = def.execute.expect("upkeep execute");
    assert_eq!(
        execute.player_scope,
        Some(PlayerFilter::Opponent),
        "each opponent loses … must set player_scope=Opponent"
    );
    match &*execute.effect {
        Effect::LoseLife { amount, .. } => match amount {
            QuantityExpr::Ref {
                qty:
                    QuantityRef::ObjectCount {
                        filter: TargetFilter::Typed(tf),
                    },
            } => {
                assert_eq!(tf.controller, Some(ControllerRef::You));
                assert!(tf
                    .type_filters
                    .contains(&TypeFilter::Subtype("Zombie".to_string())));
            }
            other => panic!("expected ObjectCount Zombies, got {other:?}"),
        },
        other => panic!("expected LoseLife, got {other:?}"),
    }
    let scry = execute.sub_ability.expect("scry sibling");
    match &*scry.effect {
        Effect::Scry { count, .. } => match count {
            QuantityExpr::Ref {
                qty:
                    QuantityRef::ObjectCount {
                        filter: TargetFilter::Typed(tf),
                    },
            } => {
                assert_eq!(tf.controller, Some(ControllerRef::You));
                assert!(tf
                    .type_filters
                    .contains(&TypeFilter::Subtype("Zombie".to_string())));
            }
            other => panic!("expected ObjectCount Zombies on Scry, got {other:?}"),
        },
        other => panic!("expected Scry, got {other:?}"),
    }
}

#[test]
fn where_x_binds_siblings_in_same_sentence() {
    // CR 107.3i: "all instances of X on an object have the same value".
    // For "target player loses X life and you gain X life, where X is ~"
    // both clauses must resolve X to the same expression, even though only
    // the second clause textually carries the binding (Essence Harvest).
    let def = parse_effect_chain(
            "Target player loses X life and you gain X life, where X is the greatest power among creatures you control.",
            AbilityKind::Spell,
        );
    // The first clause should be LoseLife with Aggregate(Max, Power, ...).
    match &*def.effect {
            Effect::LoseLife { amount, .. } => match amount {
                QuantityExpr::Ref {
                    qty: QuantityRef::Aggregate { .. },
                } => {}
                other => panic!(
                    "expected LoseLife amount to be Aggregate (propagated from sibling where-X), got {other:?}"
                ),
            },
            other => panic!("expected LoseLife, got {other:?}"),
        }
    // The sibling GainLife must also resolve to the same aggregate.
    let sub = def.sub_ability.as_ref().expect("sibling gain_life");
    match &*sub.effect {
        Effect::GainLife { amount, .. } => match amount {
            QuantityExpr::Ref {
                qty: QuantityRef::Aggregate { .. },
            } => {}
            other => panic!("expected GainLife Aggregate, got {other:?}"),
        },
        other => panic!("expected GainLife, got {other:?}"),
    }
}

