// CR 107.3i + CR 109.4 + CR 109.5: A "search ... for up to X ..., where X
// is the number of {players|opponents} who control more <filter> than you"
// clause must bind the `UpTo` search count's inner `Variable("X")` to the
// comparative-control population (Oreskos Explorer and every card in the
// class), not leave it as a 0-resolving `Variable`. This exercises the
// `apply_where_x_effect_expression` → `apply_where_x_quantity_expression`
// UpTo recursion that routes the where-clause through the shared
// `ControlsCount` quantity combinator.
/// Issue #1965 — Eldritch Evolution: "creature card with mana value X or
/// less, where X is 2 plus the sacrificed creature's mana value" must bind
/// the search filter's `Cmc` bound to the cost-paid sacrifice, not leave
/// `Variable("X")` (which resolves to 0 and skips the search).
#[test]
fn eldritch_evolution_search_binds_sacrificed_creature_mana_value_plus_two() {
    let def = parse_effect_chain_with_context(
            "Search your library for a creature card with mana value X or less, where X is 2 plus the sacrificed creature's mana value. Put that card onto the battlefield, then shuffle. Exile Eldritch Evolution.",
            AbilityKind::Spell,
            &mut ParseContext::default(),
        );
    let Effect::SearchLibrary { filter, .. } = &*def.effect else {
        panic!("expected SearchLibrary, got {:?}", def.effect);
    };
    let TargetFilter::Typed(typed) = filter else {
        panic!("expected typed filter, got {filter:?}");
    };
    assert!(typed.type_filters.contains(&TypeFilter::Creature));
    let cmc = typed
        .properties
        .iter()
        .find_map(|p| match p {
            FilterProp::Cmc { comparator, value } => Some((comparator, value)),
            _ => None,
        })
        .expect("expected Cmc bound");
    assert_eq!(*cmc.0, Comparator::LE);
    assert_eq!(
        *cmc.1,
        QuantityExpr::Offset {
            inner: Box::new(QuantityExpr::Ref {
                qty: QuantityRef::ObjectManaValue {
                    scope: ObjectScope::CostPaidObject,
                },
            }),
            offset: 2,
        }
    );
}

#[test]
fn search_up_to_x_where_x_is_players_who_control_more_lands_binds_controls_count() {
    use crate::types::ability::PlayerRelation;
    let def = parse_effect_chain_with_context(
            "Search your library for up to X Plains cards, where X is the number of players who control more lands than you. Reveal those cards, put them into your hand, then shuffle.",
            AbilityKind::Spell,
            &mut ParseContext::default(),
        );

    let Effect::SearchLibrary { count, .. } = &*def.effect else {
        panic!("expected SearchLibrary, got {:?}", def.effect);
    };
    let QuantityExpr::UpTo { max } = count else {
        panic!("expected UpTo count, got {count:?}");
    };
    let QuantityExpr::Ref {
        qty:
            QuantityRef::PlayerCount {
                filter:
                    PlayerFilter::ControlsCount {
                        relation,
                        filter,
                        comparator,
                        count: inner_count,
                    },
            },
    } = max.as_ref()
    else {
        panic!("expected UpTo(PlayerCount(ControlsCount)), got {max:?}");
    };
    assert_eq!(*relation, PlayerRelation::All);
    assert_eq!(*comparator, Comparator::GT);
    let TargetFilter::Typed(bare) = filter else {
        panic!("expected typed land filter, got {filter:?}");
    };
    assert_eq!(bare.type_filters, vec![TypeFilter::Land]);
    assert_eq!(
        bare.controller, None,
        "the compared population's filter must be controller-free"
    );
    // The comparison reads the controller's own land count (CR 109.5 "you").
    let QuantityExpr::Ref {
        qty:
            QuantityRef::ObjectCount {
                filter: TargetFilter::Typed(you_filter),
            },
    } = inner_count.as_ref()
    else {
        panic!("expected ObjectCount(you) inner count, got {inner_count:?}");
    };
    assert_eq!(you_filter.type_filters, vec![TypeFilter::Land]);
    assert_eq!(you_filter.controller, Some(ControllerRef::You));
}

/// Issue #1526 — Harvest Season: "up to X basic land cards, where X is the
/// number of tapped creatures you control" must bind X to an ObjectCount of
/// tapped creatures, not swallow the trailing put-step into the variable name.
#[test]
fn search_harvest_season_where_x_is_tapped_creature_count() {
    use crate::types::ability::{FilterProp, TypeFilter};
    let def = parse_effect_chain_with_context(
            "Search your library for up to X basic land cards, where X is the number of tapped creatures you control, put those cards onto the battlefield tapped, then shuffle.",
            AbilityKind::Spell,
            &mut ParseContext::default(),
        );

    let Effect::SearchLibrary { count, filter, .. } = &*def.effect else {
        panic!("expected SearchLibrary, got {:?}", def.effect);
    };
    let QuantityExpr::UpTo { max } = count else {
        panic!("expected UpTo count, got {count:?}");
    };
    let QuantityExpr::Ref {
        qty:
            QuantityRef::ObjectCount {
                filter: TargetFilter::Typed(creature_filter),
            },
    } = max.as_ref()
    else {
        panic!("expected UpTo(ObjectCount(tapped creatures)), got {max:?}");
    };
    assert_eq!(creature_filter.type_filters, vec![TypeFilter::Creature]);
    assert!(
        creature_filter
            .properties
            .iter()
            .any(|p| matches!(p, FilterProp::Tapped)),
        "expected tapped filter, got {:?}",
        creature_filter.properties
    );
    assert_eq!(creature_filter.controller, Some(ControllerRef::You));
    let TargetFilter::Typed(land_filter) = filter else {
        panic!("expected typed land filter, got {filter:?}");
    };
    assert_eq!(land_filter.type_filters, vec![TypeFilter::Land]);
    assert!(
        land_filter.properties.iter().any(|p| matches!(
            p,
            FilterProp::HasSupertype {
                value: Supertype::Basic
            }
        )),
        "expected basic supertype, got {:?}",
        land_filter.properties
    );
    let put = def
        .sub_ability
        .as_deref()
        .expect("Harvest Season must chain ChangeZone put-step");
    match &*put.effect {
        Effect::ChangeZone {
            destination,
            enter_tapped,
            ..
        } => {
            assert_eq!(*destination, Zone::Battlefield);
            assert!(enter_tapped.is_tapped());
        }
        other => panic!("expected ChangeZone to battlefield, got {other:?}"),
    }
}

