/// Issue #327: The second sub-ability in Skrelv's chain grants `Toxic 1`
/// and `HexproofFrom(ChosenColor)` to the chosen creature. The
/// HexproofFrom payload must be the typed `ChosenColor` variant, not the
/// stringly-typed `CardType("that color")` fallback.
#[test]
fn skrelv_hexproof_from_chosen_color_uses_typed_variant() {
    use crate::types::keywords::{HexproofFilter, Keyword};
    let def = parse_effect_chain(
            "Choose a color. Another target creature you control gains toxic 1 and hexproof from that color until end of turn. It can't be blocked by creatures of that color this turn.",
            AbilityKind::Activated,
        );
    let grant = def
        .sub_ability
        .as_ref()
        .expect("must have sub_ability (Choose -> grant)");
    let Effect::GenericEffect {
        static_abilities, ..
    } = &*grant.effect
    else {
        panic!("expected GenericEffect, got {:?}", grant.effect);
    };
    let has_typed_hexproof = static_abilities
        .iter()
        .flat_map(|s| &s.modifications)
        .any(|m| {
            matches!(
                m,
                ContinuousModification::AddKeyword {
                    keyword: Keyword::HexproofFrom(HexproofFilter::ChosenColor),
                }
            )
        });
    assert!(
        has_typed_hexproof,
        "expected HexproofFrom(ChosenColor) typed variant, got {:?}",
        static_abilities
            .iter()
            .flat_map(|s| s.modifications.iter())
            .collect::<Vec<_>>()
    );
}

/// Issue #331: Inline conjunctive grants must parse both the keyword grant
/// and the trailing restriction grant when they share one sentence.
#[test]
fn sungold_style_inline_grant_keeps_hexproof_and_cant_be_blocked() {
    use crate::types::keywords::{HexproofFilter, Keyword};
    use crate::types::statics::StaticMode;

    let def = parse_effect_chain(
            "Choose a color. This creature gains hexproof from that color until end of turn and can't be blocked by creatures of that color this turn.",
            AbilityKind::Activated,
        );
    let grant = def
        .sub_ability
        .as_ref()
        .expect("must have sub_ability (Choose -> inline grant)");
    let Effect::GenericEffect {
        static_abilities, ..
    } = &*grant.effect
    else {
        panic!("expected GenericEffect, got {:?}", grant.effect);
    };
    let modifications: Vec<_> = static_abilities
        .iter()
        .flat_map(|s| s.modifications.iter())
        .collect();
    assert!(
        modifications.iter().any(|m| {
            matches!(
                m,
                ContinuousModification::AddKeyword {
                    keyword: Keyword::HexproofFrom(HexproofFilter::ChosenColor),
                }
            )
        }),
        "expected typed HexproofFrom(ChosenColor), got {modifications:?}"
    );
    let Some(filter) = modifications.iter().find_map(|m| match m {
        ContinuousModification::AddStaticMode {
            mode: StaticMode::CantBeBlockedBy { filter },
        } => Some(filter),
        _ => None,
    }) else {
        panic!("expected AddStaticMode(CantBeBlockedBy), got {modifications:?}");
    };
    let TargetFilter::Typed(tf) = filter else {
        panic!("expected typed filter, got {filter:?}");
    };
    assert!(
        tf.properties
            .iter()
            .any(|prop| matches!(prop, FilterProp::IsChosenColor)),
        "filter must contain IsChosenColor, got {:?}",
        tf.properties
    );
}

