fn effect_add_mana_of_that_type_instead_reuses_parent_production() {
    let def = parse_effect_chain(
            "Add one mana of any type that a land you control could produce. If ~ has a +1/+1 counter on it, add three mana of that type instead.",
            AbilityKind::Activated,
        );
    match def.effect.as_ref() {
        Effect::Mana {
            produced:
                ManaProduction::AnyTypeProduceableBy {
                    count: QuantityExpr::Fixed { value: 1 },
                    land_filter,
                },
            ..
        } => {
            let tf = typed_leg(land_filter).expect("land filter should be typed");
            assert!(has_type(tf, TypeFilter::Land));
            assert_eq!(tf.controller, Some(ControllerRef::You));
        }
        other => panic!("expected base AnyTypeProduceableBy mana, got {other:?}"),
    }
    let sub = def
        .sub_ability
        .as_ref()
        .expect("conditional instead mana should be chained");
    assert!(matches!(
        sub.condition,
        Some(AbilityCondition::ConditionInstead { .. })
    ));
    match sub.effect.as_ref() {
        Effect::Mana {
            produced:
                ManaProduction::AnyTypeProduceableBy {
                    count: QuantityExpr::Fixed { value: 3 },
                    land_filter,
                },
            ..
        } => {
            let tf = typed_leg(land_filter).expect("land filter should be typed");
            assert!(has_type(tf, TypeFilter::Land));
            assert_eq!(tf.controller, Some(ControllerRef::You));
        }
        other => panic!("expected replacement AnyTypeProduceableBy mana, got {other:?}"),
    }
}

#[test]
fn effect_add_colorless_instead_if_card_exiled_with_source() {
    let def = parse_effect_chain(
        "Add {C}. If a card is exiled with ~, add {C}{C} instead.",
        AbilityKind::Activated,
    );
    assert!(matches!(
        def.effect.as_ref(),
        Effect::Mana {
            produced: ManaProduction::Colorless {
                count: QuantityExpr::Fixed { value: 1 },
            },
            ..
        }
    ));

    let sub = def
        .sub_ability
        .as_ref()
        .expect("conditional instead mana should be chained");
    match &sub.condition {
        Some(AbilityCondition::ConditionInstead { inner }) => match inner.as_ref() {
            AbilityCondition::QuantityCheck {
                lhs:
                    QuantityExpr::Ref {
                        qty: QuantityRef::CardsExiledBySource,
                    },
                comparator: Comparator::GE,
                rhs: QuantityExpr::Fixed { value: 1 },
            } => {}
            other => panic!("expected CardsExiledBySource gate, got {other:?}"),
        },
        other => panic!("expected ConditionInstead, got {other:?}"),
    }
    assert!(matches!(
        sub.effect.as_ref(),
        Effect::Mana {
            produced: ManaProduction::Colorless {
                count: QuantityExpr::Fixed { value: 2 },
            },
            ..
        }
    ));
}

