#[test]
fn bounty_of_the_hunt_schedules_cleanup_counter_removal() {
    use crate::types::ability::AbilityKind;

    let def = parse_effect_chain(
            "Distribute three +1/+1 counters among one, two, or three target creatures. For each +1/+1 counter you put on a creature this way, remove a +1/+1 counter from that creature at the beginning of the next cleanup step.",
            AbilityKind::Spell,
        );
    let sub = def
        .sub_ability
        .as_ref()
        .expect("cleanup removal sub-ability");
    match &*sub.effect {
        Effect::CreateDelayedTrigger {
            condition, effect, ..
        } => {
            assert_eq!(
                *condition,
                DelayedTriggerCondition::AtNextPhase {
                    phase: Phase::Cleanup,
                }
            );
            match &*effect.effect {
                Effect::RemoveCounter { .. } => {}
                other => panic!("expected RemoveCounter, got {other:?}"),
            }
        }
        other => panic!("expected CreateDelayedTrigger sub-ability, got {other:?}"),
    }
}

/// CR 603.7a: #638 Arcane Denial — "the next turn's upkeep" is the
/// natural-language equivalent of "the next upkeep" and must produce the
/// same `AtNextPhase { Upkeep }` delayed trigger. Covers the ~15-card
/// class (Arcane Denial + Bag of Holding artifact family).
#[test]
fn strip_temporal_suffix_next_turns_upkeep() {
    let (text, cond) =
        strip_temporal_suffix("you draw a card at the beginning of the next turn's upkeep");
    assert_eq!(text, "you draw a card");
    assert_eq!(
        cond,
        Some(DelayedTriggerCondition::AtNextPhase {
            phase: Phase::Upkeep,
        })
    );
}

/// CR 505.1 + CR 603.7a: "at the beginning of your next main phase" produces
/// `AtNextPhaseForPlayer` — controller-scoped variant. The `player` field
/// is a `PlayerId(0)` placeholder rewritten by
/// `effects::delayed_trigger::resolve` at resolution time. Used by Mana
/// Sculpt's delayed mana generation.
#[test]
fn strip_temporal_suffix_your_next_main_phase() {
    let (text, cond) = strip_temporal_suffix(
            "add an amount of {C} equal to the amount of mana spent to cast that spell at the beginning of your next main phase",
        );
    assert_eq!(
        text,
        "add an amount of {C} equal to the amount of mana spent to cast that spell"
    );
    assert_eq!(
        cond,
        Some(DelayedTriggerCondition::AtNextPhaseForPlayer {
            phase: Phase::PreCombatMain,
            player: crate::types::player::PlayerId(0),
        })
    );
}

