#[test]
fn temporal_prefix_in_effect_chain() {
    // Teferi, Hero of Dominaria +1 pattern
    let def = parse_effect_chain(
        "At the beginning of the next end step, untap up to two lands.",
        AbilityKind::Activated,
    );
    assert!(
        matches!(*def.effect, Effect::CreateDelayedTrigger { .. }),
        "Expected CreateDelayedTrigger, got {:?}",
        def.effect
    );
    if let Effect::CreateDelayedTrigger {
        condition, effect, ..
    } = &*def.effect
    {
        assert_eq!(
            *condition,
            DelayedTriggerCondition::AtNextPhase { phase: Phase::End }
        );
        assert!(
            matches!(
                *effect.effect,
                Effect::SetTapState {
                    scope: EffectScope::Single,
                    state: TapStateChange::Untap,
                    ..
                }
            ),
            "Inner effect should be Untap, got {:?}",
            effect.effect
        );
    }
}

#[test]
fn non_targeted_multi_untap_chooses_at_resolution() {
    let def = parse_effect_chain(
        "Draw two cards, then discard two cards. Untap up to three lands.",
        AbilityKind::Spell,
    );

    let untap = def
        .sub_ability
        .as_ref()
        .and_then(|discard| discard.sub_ability.as_ref())
        .expect("Frantic Search should chain to an untap instruction");
    assert!(matches!(
        &*untap.effect,
        Effect::SetTapState {
            scope: EffectScope::Single,
            state: TapStateChange::Untap,
            ..
        }
    ));
    assert_eq!(untap.target_choice_timing, TargetChoiceTiming::Resolution);
    assert_eq!(
        untap.multi_target,
        Some(MultiTargetSpec::up_to(QuantityExpr::Fixed { value: 3 }))
    );
}

/// CR 608.2c + CR 603.7a + CR 505.1 + CR 601.2h: Mana Sculpt end-to-end.
///
/// "Counter target spell. If you control a Wizard, add an amount of {C}
/// equal to the amount of mana spent to cast that spell at the beginning
/// of your next main phase."
///
/// Asserts the full typed parse:
/// - primary effect is `Counter` targeting stack spell,
/// - sub_ability carries `QuantityCheck(ObjectCount{Wizard} GE 1)` at
///   the OUTER level (the Wizard gate evaluates at spell resolution per
///   CR 608.2c, not at delayed-trigger firing),
/// - sub_ability's effect is `CreateDelayedTrigger` with
///   `AtNextPhaseForPlayer { PreCombatMain, PlayerId(0) /* placeholder */ }`,
/// - delayed trigger's inner effect is `Mana { Colorless { count:
///   Ref(triggering-spell spent-mana) } }`.
#[test]
fn mana_sculpt_full_parse_tree() {
    let def = parse_effect_chain(
            "Counter target spell. If you control a Wizard, add an amount of {C} equal to the amount of mana spent to cast that spell at the beginning of your next main phase.",
            AbilityKind::Spell,
        );
    // Primary effect: Counter.
    assert!(
        matches!(*def.effect, Effect::Counter { .. }),
        "Expected Counter primary effect, got {:?}",
        def.effect
    );

    // Sub_ability carries the Wizard gate at the OUTER level.
    let sub = def.sub_ability.as_ref().expect("sub_ability must exist");
    let sub_cond = sub
        .condition
        .as_ref()
        .expect("sub_ability must carry the Wizard gate at its outer condition");
    match sub_cond {
        crate::types::ability::AbilityCondition::QuantityCheck {
            lhs,
            comparator,
            rhs,
        } => {
            assert!(
                matches!(
                    lhs,
                    QuantityExpr::Ref {
                        qty: QuantityRef::ObjectCount { .. }
                    }
                ),
                "expected ObjectCount LHS, got {:?}",
                lhs
            );
            assert_eq!(*comparator, crate::types::ability::Comparator::GE);
            assert_eq!(*rhs, QuantityExpr::Fixed { value: 1 });
        }
        other => panic!("expected QuantityCheck on outer sub_ability, got {other:?}"),
    }

    // Sub_ability effect: CreateDelayedTrigger at PreCombatMain.
    let Effect::CreateDelayedTrigger {
        condition: delayed_cond,
        effect: delayed_effect_def,
        ..
    } = &*sub.effect
    else {
        panic!(
            "expected CreateDelayedTrigger on sub_ability, got {:?}",
            sub.effect
        );
    };
    assert!(
        matches!(
            delayed_cond,
            DelayedTriggerCondition::AtNextPhaseForPlayer {
                phase: Phase::PreCombatMain,
                ..
            }
        ),
        "expected AtNextPhaseForPlayer(PreCombatMain), got {delayed_cond:?}"
    );

    // Inner delayed effect: Mana(Colorless, Ref(triggering-spell spent-mana)).
    let Effect::Mana { produced, .. } = &*delayed_effect_def.effect else {
        panic!(
            "expected Mana effect on delayed trigger, got {:?}",
            delayed_effect_def.effect
        );
    };
    match produced {
        ManaProduction::Colorless { count } => {
            assert_eq!(
                *count,
                QuantityExpr::Ref {
                    qty: QuantityRef::ManaSpentToCast {
                        scope: crate::types::ability::CastManaObjectScope::TriggeringSpell,
                        metric: crate::types::ability::CastManaSpentMetric::Total
                    }
                },
                "Colorless count must reference mana spent on triggering spell"
            );
        }
        other => panic!("expected Colorless mana production, got {other:?}"),
    }
}

/// CR 701.6 + CR 603.7 + CR 202.3 + CR 608.2c: Full parse tree for Mana
/// Drain. Verifies that prefix-position "At the beginning of your next
/// main phase, …" wraps the inner effect in CreateDelayedTrigger, and
/// that "that spell's mana value" parses to
/// `ObjectManaValue{Anaphoric}` — the bare-anaphoric-possessive class
/// (CR 608.2c instruction-order referent), routed by
/// `classify_possessive_referent` to the runtime arm that consults
/// `effect_context_object` (the counter-target spell snapshot) first.
///
/// Asserts:
/// - primary effect is `Counter` targeting stack spell,
/// - sub_ability's effect is `CreateDelayedTrigger` with
///   `AtNextPhaseForPlayer { PreCombatMain, PlayerId(0) /* placeholder */ }`,
/// - delayed trigger's inner effect is `Mana { Colorless { count:
///   Ref(ObjectManaValue{CostPaidObject}) } }`.
#[test]
fn mana_drain_full_parse_tree() {
    let def = parse_effect_chain(
            "Counter target spell. At the beginning of your next main phase, add an amount of {C} equal to that spell's mana value.",
            AbilityKind::Spell,
        );

    // Primary effect: Counter.
    assert!(
        matches!(*def.effect, Effect::Counter { .. }),
        "Expected Counter primary effect, got {:?}",
        def.effect
    );

    // Sub_ability effect: CreateDelayedTrigger at PreCombatMain.
    let sub = def.sub_ability.as_ref().expect("sub_ability must exist");
    let Effect::CreateDelayedTrigger {
        condition: delayed_cond,
        effect: delayed_effect_def,
        ..
    } = &*sub.effect
    else {
        panic!(
            "expected CreateDelayedTrigger on sub_ability, got {:?}",
            sub.effect
        );
    };
    assert!(
        matches!(
            delayed_cond,
            DelayedTriggerCondition::AtNextPhaseForPlayer {
                phase: Phase::PreCombatMain,
                ..
            }
        ),
        "expected AtNextPhaseForPlayer(PreCombatMain), got {delayed_cond:?}"
    );

    // Inner delayed effect: Mana(Colorless, Ref(ObjectManaValue{Demonstrative})).
    //
    // CR 608.2c — "that spell" in the delayed-trigger clause is a bare
    // demonstrative possessive: it points at the spell introduced by the
    // earlier-instruction `Counter target spell`. `classify_possessive_referent`
    // emits `ObjectScope::Demonstrative` (the noun-phrase referent, distinct
    // from the pronoun "its") whose runtime resolver (in `game/quantity.rs`)
    // consults `effect_context_object` (the captured-on-counter spell
    // snapshot stamped by the parent chain) before falling back to the
    // trigger-event source / cost_paid_object. The dedicated variant keeps
    // the subject-injection rewrite from rebinding this fixed antecedent.
    // The integration test `mana_drain_refund.rs` exercises the runtime
    // end-to-end; this parser assertion just freezes the parse-time scope.
    let Effect::Mana { produced, .. } = &*delayed_effect_def.effect else {
        panic!(
            "expected Mana effect on delayed trigger, got {:?}",
            delayed_effect_def.effect
        );
    };
    match produced {
        ManaProduction::Colorless { count } => {
            assert_eq!(
                *count,
                QuantityExpr::Ref {
                    qty: QuantityRef::ObjectManaValue {
                        scope: crate::types::ability::ObjectScope::Demonstrative,
                    }
                },
                "Colorless count must reference the counter-target spell's \
                     mana value via ObjectManaValue{{Demonstrative}} (CR 608.2c \
                     instruction-order referent)"
            );
        }
        other => panic!("expected Colorless mana production, got {other:?}"),
    }
}

/// CR 608.2c regression guard: a delayed-trigger effect chain WITHOUT an
/// inner condition must still parse correctly after the condition-lift.
/// The outer `CreateDelayedTrigger`-carrying `AbilityDefinition` has
/// `condition: None` (nothing to lift), and the inner `AbilityDefinition`
/// also has `condition: None`.
#[test]
fn delayed_trigger_without_inner_condition_lift_is_noop() {
    let def = parse_effect_chain(
        "Untap target creature at the beginning of the next end step.",
        AbilityKind::Spell,
    );
    assert!(
        def.condition.is_none(),
        "outer AbilityDefinition must carry no condition when none was present on inner"
    );
    let Effect::CreateDelayedTrigger { effect, .. } = &*def.effect else {
        panic!("expected CreateDelayedTrigger, got {:?}", def.effect);
    };
    assert!(
        effect.condition.is_none(),
        "inner AbilityDefinition must carry no condition when none was present originally"
    );
}

/// CR 701.20b + CR 608.2c + CR 608.2b: Zimone's Experiment end-to-end.
///
/// `"Look at the top five cards of your library. You may reveal up to two
/// creature and/or land cards from among them, then put the rest on the
/// bottom of your library in a random order. Put all land cards revealed
/// this way onto the battlefield tapped and put all creature cards
/// revealed this way into your hand."`
///
/// Asserts the full compound parse tree:
/// - Top-level `Dig` with `count=5, keep_count=Some(2), up_to=true,
///   reveal=true, filter=Or([Creature, Land]), destination=None (no
///   auto-route), rest_destination=Some(Library)`.
/// - Sub_ability chain routes revealed cards by type through
///   `TargetFilter::TrackedSetFiltered`: lands enter battlefield tapped;
///   creatures go to hand.
#[test]
fn zimones_experiment_full_parse_tree() {
    let def = parse_effect_chain(
            "Look at the top five cards of your library. You may reveal up to two creature and/or land cards from among them, then put the rest on the bottom of your library in a random order. Put all land cards revealed this way onto the battlefield tapped and put all creature cards revealed this way into your hand.",
            AbilityKind::Spell,
        );
    // Top-level: Dig, patched by the reveal-only DigFromAmong continuation.
    let Effect::Dig {
        count,
        keep_count,
        up_to,
        reveal,
        filter,
        destination,
        rest_destination,
        ..
    } = &*def.effect
    else {
        panic!("expected Effect::Dig at top level, got {:?}", def.effect);
    };
    assert_eq!(*count, QuantityExpr::Fixed { value: 5 });
    assert_eq!(*keep_count, Some(2));
    assert!(*up_to, "up_to must be true (reveal up to two)");
    assert!(*reveal, "reveal must be true (reveal-form continuation)");
    assert_eq!(
        *destination, None,
        "destination must be None (reveal-only; downstream sub_abilities route by type)"
    );
    assert_eq!(*rest_destination, Some(crate::types::zones::Zone::Library));
    // Filter must be Or { [Creature, Land] }.
    match filter {
        TargetFilter::Or { filters } => {
            assert_eq!(filters.len(), 2);
            assert!(filters.iter().any(
                    |f| matches!(f, TargetFilter::Typed(tf) if tf.type_filters == vec![TypeFilter::Creature])
                ));
            assert!(filters.iter().any(
                    |f| matches!(f, TargetFilter::Typed(tf) if tf.type_filters == vec![TypeFilter::Land])
                ));
        }
        other => panic!("expected Or {{ [Creature, Land] }}, got {other:?}"),
    }

    // First sub_ability: ChangeZoneAll { TrackedSetFiltered(Land) → Battlefield tapped }.
    let sub1 = def
        .sub_ability
        .as_ref()
        .expect("first sub_ability (Land routing) must exist");
    let Effect::ChangeZoneAll {
        destination: dest1,
        target: target1,
        enter_tapped,
        ..
    } = &*sub1.effect
    else {
        panic!(
            "expected ChangeZoneAll in first sub_ability, got {:?}",
            sub1.effect
        );
    };
    assert_eq!(*dest1, crate::types::zones::Zone::Battlefield);
    assert!(
        enter_tapped.is_tapped(),
        "lands must enter battlefield tapped"
    );
    match target1 {
        TargetFilter::TrackedSetFiltered { filter, .. } => match filter.as_ref() {
            TargetFilter::Typed(tf) => {
                assert_eq!(tf.type_filters, vec![TypeFilter::Land]);
            }
            other => panic!("expected Typed(Land), got {other:?}"),
        },
        other => panic!("expected TrackedSetFiltered, got {other:?}"),
    }

    // Second sub_ability: ChangeZoneAll { TrackedSetFiltered(Creature) → Hand }.
    let sub2 = sub1
        .sub_ability
        .as_ref()
        .expect("second sub_ability (Creature routing) must exist");
    let Effect::ChangeZoneAll {
        destination: dest2,
        target: target2,
        ..
    } = &*sub2.effect
    else {
        panic!(
            "expected ChangeZoneAll in second sub_ability, got {:?}",
            sub2.effect
        );
    };
    assert_eq!(*dest2, crate::types::zones::Zone::Hand);
    match target2 {
        TargetFilter::TrackedSetFiltered { filter, .. } => match filter.as_ref() {
            TargetFilter::Typed(tf) => {
                assert_eq!(tf.type_filters, vec![TypeFilter::Creature]);
            }
            other => panic!("expected Typed(Creature), got {other:?}"),
        },
        other => panic!("expected TrackedSetFiltered, got {other:?}"),
    }
}

/// SHAPE — Winding Way (issue #2931): "Choose creature or land. Reveal the
/// top four cards of your library. Put all cards of the chosen type revealed
/// this way into your hand and the rest into your graveyard."
///
/// The reveal-and-partition chain must lower to:
/// - `Choose` (creature/land card-type choice) → `RevealTop { count: 4 }`
///   → `ChangeZoneAll { origin: None, TrackedSetFiltered(IsChosenCardType) →
///   Hand }` → `ChangeZoneAll { origin: None, TrackedSet → Graveyard }`.
///
/// Three regressions are guarded here (CR 205.2a / CR 608.2c / CR 701.20b):
/// 1. The chosen-type filter is `IsChosenCardType` (a card-typed base, not
///    `IsChosenCreatureType`) so it can match the chosen Creature/Land type.
/// 2. The chosen-type move's `origin` is `None` — a tracked-set anaphor names
///    the revealed cards regardless of zone; inferring Graveyard from the
///    "into your graveyard" rest phrase made the move scan the wrong zone.
/// 3. The "and the rest into your graveyard" complement is materialized as a
///    sibling `ChangeZoneAll { TrackedSetFiltered(Not(chosen)) → Graveyard }`
///    (it had been dropped). Negating the chosen filter keeps the complement
///    zone- and order-independent — it never re-moves the chosen cards.
#[test]
fn winding_way_reveal_partition_full_parse_tree() {
    let def = parse_effect_chain(
            "Choose creature or land. Reveal the top four cards of your library. Put all cards of the chosen type revealed this way into your hand and the rest into your graveyard.",
            AbilityKind::Spell,
        );

    assert!(
        matches!(&*def.effect, Effect::Choose { .. }),
        "top-level must be the creature/land Choose, got {:?}",
        def.effect
    );

    let reveal = def
        .sub_ability
        .as_ref()
        .expect("Choose must chain to RevealTop");
    let Effect::RevealTop { count, .. } = &*reveal.effect else {
        panic!("expected RevealTop, got {:?}", reveal.effect);
    };
    assert_eq!(*count, 4, "reveal the top four cards");

    // Chosen-type move: TrackedSetFiltered(IsChosenCardType) → Hand, origin None.
    let chosen = reveal
        .sub_ability
        .as_ref()
        .expect("RevealTop must chain to the chosen-type move");
    let Effect::ChangeZoneAll {
        origin: chosen_origin,
        destination: chosen_dest,
        target: chosen_target,
        ..
    } = &*chosen.effect
    else {
        panic!(
            "expected ChangeZoneAll for the chosen-type move, got {:?}",
            chosen.effect
        );
    };
    assert_eq!(
        *chosen_origin, None,
        "tracked-set anaphor move must leave origin unset (derived from members)"
    );
    assert_eq!(*chosen_dest, crate::types::zones::Zone::Hand);
    match chosen_target {
        TargetFilter::TrackedSetFiltered { filter, .. } => match filter.as_ref() {
            TargetFilter::Typed(tf) => assert!(
                tf.properties.contains(&FilterProp::IsChosenCardType),
                "chosen-type filter must be IsChosenCardType (card-typed base), got {:?}",
                tf.properties
            ),
            other => panic!("expected Typed filter inside TrackedSetFiltered, got {other:?}"),
        },
        other => panic!("expected TrackedSetFiltered target, got {other:?}"),
    }

    // Rest complement: TrackedSet → Graveyard, origin None.
    let rest = chosen
        .sub_ability
        .as_ref()
        .expect("chosen-type move must chain the rest complement");
    let Effect::ChangeZoneAll {
        origin: rest_origin,
        destination: rest_dest,
        target: rest_target,
        ..
    } = &*rest.effect
    else {
        panic!(
            "expected ChangeZoneAll for the rest complement, got {:?}",
            rest.effect
        );
    };
    assert_eq!(*rest_origin, None);
    assert_eq!(
        *rest_dest,
        crate::types::zones::Zone::Graveyard,
        "the rest move to the graveyard"
    );
    // The complement excludes the chosen subset by predicate (Not(chosen)),
    // so it never re-moves a card already routed to hand.
    match rest_target {
        TargetFilter::TrackedSetFiltered { filter, .. } => assert!(
            matches!(filter.as_ref(), TargetFilter::Not { .. }),
            "rest complement must negate the chosen filter, got {filter:?}"
        ),
        other => panic!("expected TrackedSetFiltered(Not(..)) for the rest, got {other:?}"),
    }
}

#[test]
fn put_discarded_card_this_way_uses_tracked_set_filter() {
    let def = parse_effect_chain(
            "Target player discards two cards. Put up to one land card discarded this way onto the battlefield tapped under your control.",
            AbilityKind::Spell,
        );

    assert!(
        matches!(&*def.effect, Effect::Discard { .. }),
        "primary effect should be Discard, got {:?}",
        def.effect
    );

    let sub = def
        .sub_ability
        .as_ref()
        .expect("discard should chain to the put-onto-battlefield effect");
    let Effect::ChangeZone {
        destination,
        target,
        enters_under,
        enter_tapped,
        up_to,
        ..
    } = &*sub.effect
    else {
        panic!("expected ChangeZone sub-ability, got {:?}", sub.effect);
    };
    assert_eq!(*destination, Zone::Battlefield);
    assert_eq!(*enters_under, Some(ControllerRef::You));
    assert!(enter_tapped.is_tapped());
    assert!(*up_to);
    match target {
        TargetFilter::TrackedSetFiltered { id, filter, .. } => {
            assert_eq!(*id, TrackedSetId(0));
            match filter.as_ref() {
                TargetFilter::Typed(tf) => {
                    assert_eq!(tf.type_filters, vec![TypeFilter::Land]);
                }
                other => panic!("expected tracked-set filter to preserve Land, got {other:?}"),
            }
        }
        other => panic!("expected TrackedSetFiltered, got {other:?}"),
    }
}

