#[test]
fn effect_koth_emblem_grants_activated_ability_to_mountains() {
    // CR 114.1 + CR 114.4: Koth of the Hammer's −5 emblem grants an
    // activated ability to a class of lands. The granted ability is nested
    // one quote level deep ('{T}: …') inside the emblem's own quotes, so the
    // emblem must strip only its OUTER quotes and promote the nested
    // single-quoted ability to a double-quoted body the grant parser
    // recognises — otherwise it falls back to an inert `EmblemStatic` blob
    // that grants nothing (the bug seen in game-state turn 34).
    let e = parse_effect(
            "You get an emblem with \"Mountains you control have '{T}: This land deals 1 damage to any target.'\"",
        );
    let Effect::CreateEmblem { statics, triggers } = e else {
        panic!("expected CreateEmblem, got {e:?}");
    };
    assert!(
        triggers.is_empty(),
        "Koth emblem is a static grant, not a trigger, got {triggers:?}"
    );
    assert_eq!(
        statics.len(),
        1,
        "expected one granted static, got {statics:?}"
    );
    let def = &statics[0];
    assert_eq!(
        def.mode,
        StaticMode::Continuous,
        "granted ability must be a Continuous layer-6 static, not the inert EmblemStatic fallback"
    );
    // CR 613.1f: layer-6 ability-adding grant affects the Mountains the
    // emblem's controller controls.
    let affected = def.affected.as_ref().expect("affected filter present");
    assert!(
        matches!(
            affected,
            TargetFilter::Typed(tf) if tf.controller == Some(ControllerRef::You)
        ),
        "granted ability must be scoped to permanents you control, got {affected:?}"
    );
    // CR 602.1: the granted ability is an activated ability (GrantAbility),
    // not a keyword or P/T buff, and it deals damage.
    let definition = def
        .modifications
        .iter()
        .find_map(|m| match m {
            ContinuousModification::GrantAbility { definition } => Some(definition),
            _ => None,
        })
        .expect("expected a GrantAbility modification granting the {T} ability");
    assert!(
        matches!(&*definition.effect, Effect::DealDamage { .. }),
        "granted ability must deal damage, got {:?}",
        definition.effect
    );
}

#[test]
fn kicker_instead_chain_produces_correct_condition() {
    let ability = parse_effect_chain(
            "~ deals 2 damage to target creature. If it was kicked, ~ deals 5 damage to that creature instead",
            AbilityKind::Spell,
        );
    assert!(matches!(
        &*ability.effect,
        Effect::DealDamage {
            amount: QuantityExpr::Fixed { value: 2 },
            ..
        }
    ));
    let sub = ability.sub_ability.as_ref().expect("expected sub_ability");
    assert_eq!(
        sub.condition,
        Some(AbilityCondition::AdditionalCostPaidInstead)
    );
    assert!(matches!(
        &*sub.effect,
        Effect::DealDamage {
            amount: QuantityExpr::Fixed { value: 5 },
            target: TargetFilter::ParentTarget,
            ..
        }
    ));
}

#[test]
fn kicker_leading_instead_produces_correct_condition() {
    // CR 608.2e: "if kicked, instead [effect]" — leading "instead" variant.
    // Must produce AdditionalCostPaidInstead, same as trailing "instead".
    let ability = parse_effect_chain(
            "Destroy target creature or planeswalker with mana value 2 or less. If this spell was kicked, instead destroy target creature or planeswalker",
            AbilityKind::Spell,
        );
    assert!(
        matches!(&*ability.effect, Effect::Destroy { .. }),
        "Base effect should be Destroy"
    );
    let sub = ability.sub_ability.as_ref().expect("expected sub_ability");
    assert_eq!(
        sub.condition,
        Some(AbilityCondition::AdditionalCostPaidInstead)
    );
    assert!(
        matches!(&*sub.effect, Effect::Destroy { .. }),
        "Kicked effect should be Destroy"
    );
}

#[test]
fn kicker_leading_instead_destroy_drops_base_mana_value_cap() {
    let ability = parse_effect_chain(
            "Destroy target creature or planeswalker with mana value 2 or less. If this spell was kicked, instead destroy target creature or planeswalker",
            AbilityKind::Spell,
        );
    let sub = ability.sub_ability.as_ref().expect("expected sub_ability");
    assert_eq!(
        sub.condition,
        Some(AbilityCondition::AdditionalCostPaidInstead)
    );

    fn filter_contains_cmc_prop(filter: &TargetFilter) -> bool {
        match filter {
            TargetFilter::Typed(typed) => typed
                .properties
                .iter()
                .any(|prop| matches!(prop, FilterProp::Cmc { .. })),
            TargetFilter::Or { filters } | TargetFilter::And { filters } => {
                filters.iter().any(filter_contains_cmc_prop)
            }
            TargetFilter::Not { filter } => filter_contains_cmc_prop(filter),
            _ => false,
        }
    }

    let Effect::Destroy { target, .. } = &*sub.effect else {
        panic!(
            "expected kicked override to be Destroy, got {:?}",
            sub.effect
        );
    };
    assert!(
        !filter_contains_cmc_prop(target),
        "kicked override target must not keep base mana-value restriction; got {0:?}",
        target,
    );
}

#[test]
fn rite_of_replication_kicker_creates_five_copies() {
    // CR 702.33d + CR 707.10: Rite of Replication's kicked mode creates
    // five copies instead of one. The "create five of those tokens" sub
    // is an anaphor to the parent CopyTokenOf clause.
    let ability = parse_effect_chain(
            "Create a token that's a copy of target creature. If this spell was kicked, create five of those tokens instead.",
            AbilityKind::Spell,
        );
    assert!(
        matches!(
            &*ability.effect,
            Effect::CopyTokenOf {
                count: QuantityExpr::Fixed { value: 1 },
                ..
            }
        ),
        "Base effect should be CopyTokenOf with count 1, got {:?}",
        ability.effect
    );
    let sub = ability.sub_ability.as_ref().expect("expected sub_ability");
    assert_eq!(
        sub.condition,
        Some(AbilityCondition::AdditionalCostPaidInstead),
        "Kicker sub should use AdditionalCostPaidInstead ('create five ... instead')"
    );
    assert!(
        matches!(
            &*sub.effect,
            Effect::CopyTokenOf {
                count: QuantityExpr::Fixed { value: 5 },
                ..
            }
        ),
        "Kicked sub should be CopyTokenOf with count 5, got {:?}",
        sub.effect
    );
}

