/// Issue #2879: the complete Escape to the Wilds oracle text parses to a
/// 3-link chain (ExileTop -> PlayFromExile grant -> additional-land
/// GenericEffect) with no Unimplemented / CastFromZone{Any}.
#[test]
fn escape_to_the_wilds_full_card_chain() {
    let def = parse_effect_chain(
            "Exile the top five cards of your library. You may play cards exiled this way until the end of your next turn. You may play an additional land this turn.",
            AbilityKind::Spell,
        );
    // Link 1: ExileTop.
    assert!(
        matches!(
            &*def.effect,
            Effect::ExileTop {
                count: QuantityExpr::Fixed { value: 5 },
                ..
            }
        ),
        "Expected ExileTop(5) root, got {:?}",
        def.effect
    );
    // Link 2: PlayFromExile grant.
    let grant = def
        .sub_ability
        .as_ref()
        .expect("Expected grant sub_ability");
    assert!(
        matches!(
            &*grant.effect,
            Effect::GrantCastingPermission {
                permission: CastingPermission::PlayFromExile { .. },
                ..
            }
        ),
        "Expected PlayFromExile grant, got {:?}",
        grant.effect
    );
    // Link 3: additional-land GenericEffect.
    let land = grant
        .sub_ability
        .as_ref()
        .expect("Expected additional-land sub_ability");
    assert!(
        !land.optional,
        "additional-land permission grant must resolve without an optional prompt"
    );
    assert!(
        matches!(&*land.effect, Effect::GenericEffect { .. }),
        "Expected GenericEffect for additional land, got {:?}",
        land.effect
    );
    // No Unimplemented / CastFromZone anywhere in the chain.
    for (label, eff) in [
        ("root", &*def.effect),
        ("grant", &*grant.effect),
        ("land", &*land.effect),
    ] {
        assert!(
            !matches!(
                eff,
                Effect::Unimplemented { .. } | Effect::CastFromZone { .. }
            ),
            "{label} must not be Unimplemented/CastFromZone, got {eff:?}"
        );
    }
}

/// Issue #4000: Dominating Licid's "you may pay {U} to end this effect" is a
/// separate termination permission, not an optional accept/decline on the
/// licid activation itself.
#[test]
fn dominating_licid_activation_is_not_optional() {
    fn ability_tree_has_optional(def: &AbilityDefinition) -> bool {
        if def.optional {
            return true;
        }
        def.sub_ability
            .as_ref()
            .is_some_and(|sub| ability_tree_has_optional(sub))
            || def
                .else_ability
                .as_ref()
                .is_some_and(|sub| ability_tree_has_optional(sub))
    }

    let def = parse_effect_chain(
            "This creature loses this ability and becomes an Aura enchantment with enchant creature. Attach it to target creature. You may pay {U} to end this effect.",
            AbilityKind::Activated,
        );
    assert!(
        !def.optional,
        "licid activation root must not be optional, got {def:?}"
    );
    assert!(
        !ability_tree_has_optional(&def),
        "no sub_ability in the licid chain may carry optional=true"
    );
}

#[test]
fn return_opponents_choice_from_your_graveyard_uses_zone_choice_chain() {
    let def = parse_effect_chain(
        "Return a nonland card of an opponent's choice from your graveyard to your hand.",
        AbilityKind::Spell,
    );

    let Effect::ChooseFromZone {
        count,
        zone,
        zone_owner,
        filter: Some(filter),
        chooser,
        up_to,
        ..
    } = &*def.effect
    else {
        panic!("expected ChooseFromZone, got {:?}", def.effect);
    };
    assert_eq!(*count, 1);
    assert_eq!(*zone, Zone::Graveyard);
    assert_eq!(*zone_owner, ZoneOwner::Controller);
    assert_eq!(*chooser, Chooser::Opponent);
    assert!(!up_to);
    let TargetFilter::Typed(typed) = filter else {
        panic!("expected typed graveyard-card filter, got {filter:?}");
    };
    assert!(typed.type_filters.contains(&TypeFilter::Card));
    assert!(typed
        .type_filters
        .contains(&TypeFilter::Non(Box::new(TypeFilter::Land))));
    assert!(typed.properties.contains(&FilterProp::InZone {
        zone: Zone::Graveyard
    }));
    assert!(typed.properties.contains(&FilterProp::Owned {
        controller: ControllerRef::You
    }));

    let sub = def.sub_ability.as_ref().expect("expected ChangeZone sub");
    assert!(matches!(
        &*sub.effect,
        Effect::ChangeZone {
            origin: None,
            destination: Zone::Hand,
            target: TargetFilter::Any,
            ..
        }
    ));
}

