/// End-to-end parser integration test for Teferi's Protection.
///
/// CR 119.7 + CR 119.8 + CR 702.16 + CR 702.26: The full Oracle text
/// exercises the compound chain parser (shared leading "Until your next
/// turn" duration), the life-lock clause (added in this batch), the
/// protection-granting clause, and the PhaseOut clause. All three must
/// chain correctly under the outer `UntilYourNextTurn` duration.
#[test]
fn parse_teferis_protection_end_to_end() {
    let result = crate::parser::parse_oracle_text(
            "Until your next turn, your life total can't change and you gain protection from everything. All permanents you control phase out.\nExile Teferi's Protection.",
            "Teferi's Protection",
            &[],
            &["Instant".to_string()],
            &[],
        );

    assert!(
        result.abilities.len() >= 2,
        "expected at least the chained spell ability and an exile ability, got {}: {:?}",
        result.abilities.len(),
        result
            .abilities
            .iter()
            .map(|a| format!("{:?}", a.effect))
            .collect::<Vec<_>>()
    );

    // First ability: the chained compound under UntilYourNextTurn.
    let first = &result.abilities[0];
    assert_eq!(
        first.duration,
        Some(Duration::UntilNextTurnOf {
            player: PlayerScope::Controller,
        })
    );

    let Effect::GenericEffect {
        static_abilities, ..
    } = &*first.effect
    else {
        panic!(
            "expected first ability effect to be GenericEffect(life-lock), got {:?}",
            first.effect
        );
    };
    let modes: Vec<_> = static_abilities.iter().map(|s| s.mode.clone()).collect();
    assert!(
        modes.contains(&StaticMode::CantGainLife),
        "first clause missing CantGainLife: {modes:?}"
    );
    assert!(
        modes.contains(&StaticMode::CantLoseLife),
        "first clause missing CantLoseLife: {modes:?}"
    );

    // Second clause: protection grant via sub_ability.
    let second = first
        .sub_ability
        .as_ref()
        .expect("life-lock clause should chain to protection clause via sub_ability");
    let Effect::GenericEffect {
        static_abilities: protection_statics,
        ..
    } = &*second.effect
    else {
        panic!(
            "expected protection clause to be GenericEffect, got {:?}",
            second.effect
        );
    };
    assert!(
        protection_statics
            .iter()
            .any(|s| s.modifications.iter().any(|m| matches!(
                m,
                ContinuousModification::AddKeyword {
                    keyword: crate::types::keywords::Keyword::Protection(_)
                }
            ))),
        "expected protection-from-everything keyword in {:?}",
        protection_statics
    );
    // CR 113.10: Player-scope grant — the static must be affected by the
    // controller (the protected player), not SelfRef (the spell object).
    assert!(
        protection_statics
            .iter()
            .any(|s| s.affected == Some(TargetFilter::Controller)),
        "protection-from-everything must target Controller (player), got {:?}",
        protection_statics
            .iter()
            .map(|s| &s.affected)
            .collect::<Vec<_>>()
    );

    // Third clause: phase out all permanents you control.
    let third = second
        .sub_ability
        .as_ref()
        .expect("protection clause should chain to phase-out clause");
    assert!(
        matches!(*third.effect, Effect::PhaseOut { .. }),
        "expected PhaseOut clause, got {:?}",
        third.effect
    );
}

/// Issue #514 + CR 608.2c: Liliana's Triumph's secondary clause
/// ("each opponent also discards a card") must lower to a real
/// `Effect::Discard` with `player_scope: Opponent` — not `Unimplemented`.
/// The leading "also" continuation adverb is stripped after the player
/// scope is resolved.
#[test]
fn liliana_triumph_secondary_clause_discards() {
    let result = crate::parser::parse_oracle_text(
            "Each opponent sacrifices a creature of their choice. If you control a Liliana planeswalker, each opponent also discards a card.",
            "Liliana's Triumph",
            &[],
            &["Sorcery".to_string()],
            &[],
        );

    let first = &result.abilities[0];
    assert!(
        matches!(*first.effect, Effect::Sacrifice { .. }),
        "expected primary clause to be Sacrifice, got {:?}",
        first.effect
    );

    let sub = first
        .sub_ability
        .as_ref()
        .expect("Liliana's Triumph should chain a sub_ability for the secondary discard");
    assert_eq!(
        sub.player_scope,
        Some(PlayerFilter::Opponent),
        "secondary clause must be scoped to each opponent"
    );
    assert!(
        matches!(sub.condition, Some(AbilityCondition::QuantityCheck { .. })),
        "secondary clause must be gated on the Liliana planeswalker QuantityCheck, got {:?}",
        sub.condition
    );

    // Discriminating assertion: the secondary clause is a real Discard
    // effect, NOT Unimplemented (the bug being fixed).
    assert!(
        !matches!(*sub.effect, Effect::Unimplemented { .. }),
        "secondary clause must not be Unimplemented, got {:?}",
        sub.effect
    );
    assert!(
        matches!(*sub.effect, Effect::Discard { .. }),
        "secondary clause must lower to Effect::Discard, got {:?}",
        sub.effect
    );
}

#[test]
fn crackling_doom_sacrifice_preserves_greatest_power_filter() {
    let def = parse_effect_chain(
            "Crackling Doom deals 2 damage to each opponent. Each opponent sacrifices a creature with the greatest power among creatures that player controls.",
            AbilityKind::Spell,
        );
    let sacrifice = def
        .sub_ability
        .as_ref()
        .expect("damage clause should chain to opponent sacrifice");
    assert_eq!(sacrifice.player_scope, Some(PlayerFilter::Opponent));
    let Effect::Sacrifice { target, count, .. } = &*sacrifice.effect else {
        panic!("expected sacrifice clause, got {:?}", sacrifice.effect);
    };
    assert_eq!(count, &QuantityExpr::Fixed { value: 1 });
    let TargetFilter::Typed(TypedFilter {
        type_filters,
        controller,
        properties,
    }) = target
    else {
        panic!("expected typed creature filter, got {0:?}", target);
    };
    assert!(type_filters.contains(&TypeFilter::Creature));
    assert_eq!(controller, &Some(ControllerRef::You));
    let superlative = properties
        .iter()
        .find_map(|prop| match prop {
            FilterProp::PtComparison {
                stat,
                scope,
                comparator,
                value,
            } => Some((stat, scope, comparator, value)),
            _ => None,
        })
        .expect("sacrifice filter should carry greatest-power property");
    assert_eq!(*superlative.0, PtStat::Power);
    assert_eq!(*superlative.1, PtValueScope::Current);
    assert_eq!(*superlative.2, Comparator::EQ);
    let QuantityExpr::Ref {
        qty:
            QuantityRef::Aggregate {
                function,
                property,
                filter,
            },
    } = superlative.3
    else {
        panic!("expected aggregate quantity, got {:?}", superlative.3);
    };
    assert_eq!(*function, AggregateFunction::Max);
    assert_eq!(*property, ObjectProperty::Power);
    let TargetFilter::Typed(TypedFilter {
        type_filters,
        controller,
        ..
    }) = filter
    else {
        panic!("expected typed aggregate filter, got {filter:?}");
    };
    assert!(type_filters.contains(&TypeFilter::Creature));
    assert_eq!(controller, &Some(ControllerRef::ScopedPlayer));
}

/// CR 113.10 + CR 702.16j: "you gain protection from everything" — the
/// player-scoped keyword grant must emit `affected: Controller` so the
/// static binds to the spell's controller at resolution time (not to the
/// spell object itself, which is destined for the graveyard).
#[test]
fn parse_you_gain_protection_from_everything_targets_controller() {
    use crate::types::ability::ContinuousModification;
    use crate::types::keywords::{Keyword, ProtectionTarget};

    let def = parse_effect_chain("you gain protection from everything", AbilityKind::Spell);
    let Effect::GenericEffect {
        static_abilities, ..
    } = &*def.effect
    else {
        panic!(
            "expected GenericEffect for 'you gain protection from everything', got {:?}",
            def.effect
        );
    };
    assert_eq!(static_abilities.len(), 1, "expected one StaticDefinition");
    let sd = &static_abilities[0];
    assert_eq!(
        sd.affected,
        Some(TargetFilter::Controller),
        "affected filter must be Controller (player-scoped), got {:?}",
        sd.affected
    );
    assert!(
        sd.modifications.iter().any(|m| matches!(
            m,
            ContinuousModification::AddKeyword {
                keyword: Keyword::Protection(ProtectionTarget::Everything)
            }
        )),
        "expected AddKeyword(Protection(Everything)) in {:?}",
        sd.modifications
    );
}

