// ── "Any player may" — group bargain / punisher (issue #3236) ──────────

/// CR 608.2d + CR 101.4: "any player may sacrifice … of their choice. If a
/// player does, …" lowers to `optional: true` + `optional_for: AnyPlayer`
/// (every player INCLUDING the controller is offered), with an
/// `OptionalEffectPerformed` sub-condition.
///
/// BLOCKER 1 regression guard: the sacrifice TargetFilter must NOT stamp
/// `controller: Some(Opponent)`. AnyPlayer leaves the actor ABSENT so the
/// runtime `obj.controller == promptee` pre-filter scopes "their own
/// permanents" per promptee — otherwise the controller could never
/// sacrifice their own land.
#[test]
fn any_player_may_sacrifice_sets_anyplayer_and_no_opponent_controller() {
    let def = parse_effect_chain(
        "any player may sacrifice a land of their choice. if a player does, \
             put this creature on top of its owner's library",
        AbilityKind::Spell,
    );
    assert!(def.optional, "should be optional");
    assert_eq!(
        def.optional_for,
        Some(crate::types::ability::OpponentMayScope::AnyPlayer),
        "should have AnyPlayer scope"
    );
    assert_ne!(
        def.optional_for,
        Some(crate::types::ability::OpponentMayScope::AnyOpponent),
        "AnyPlayer must NOT be AnyOpponent (controller is included)"
    );
    assert!(
        matches!(*def.effect, Effect::Sacrifice { .. }),
        "effect should be Sacrifice, got {:?}",
        def.effect
    );
    // BLOCKER 1: controller must NOT be baked to Opponent — it must be None
    // (promptee-scoped at runtime).
    if let Effect::Sacrifice { ref target, .. } = *def.effect {
        match target {
            TargetFilter::Typed(tf) => {
                assert_eq!(
                    tf.controller, None,
                    "BLOCKER 1: AnyPlayer sacrifice must leave controller \
                         absent (None), not stamp Opponent — got {:?}",
                    tf.controller
                );
            }
            other => panic!("expected Typed filter, got {other:?}"),
        }
    }
    // "if a player does" → OptionalEffectPerformed sub-condition.
    let sub = def.sub_ability.as_ref().expect("should have sub_ability");
    assert_eq!(
        sub.condition,
        Some(AbilityCondition::effect_performed()),
        "sub condition should be OptionalEffectPerformed (if a player does)"
    );
    // The "put this creature on top of its owner's library" consequence must
    // parse cleanly (no Unimplemented) so the card flips to supported.
    assert!(
        !matches!(*sub.effect, Effect::Unimplemented { .. }),
        "if-a-player-does consequence must not be Unimplemented, got {:?}",
        sub.effect
    );
}

/// CR 608.2d + CR 101.4: Browbeat-class — "any player may have ~ deal 5
/// damage to them. If no one does, target player draws three cards." The
/// reward attaches as the `else_ability` on the OptionalEffectPerformed sub.
#[test]
fn any_player_may_have_deal_damage_with_if_no_one_does_reward() {
    let def = parse_effect_chain(
        "any player may have ~ deal 5 damage to them. if no one does, \
             target player draws three cards",
        AbilityKind::Spell,
    );
    assert!(def.optional, "should be optional");
    assert_eq!(
        def.optional_for,
        Some(crate::types::ability::OpponentMayScope::AnyPlayer),
        "should have AnyPlayer scope"
    );
    assert_ne!(
        def.optional_for,
        Some(crate::types::ability::OpponentMayScope::AnyOpponent),
    );
    assert!(
        matches!(*def.effect, Effect::DealDamage { .. }),
        "effect should be DealDamage, got {:?}",
        def.effect
    );
    // Standalone "if no one does" has no "if a player does" head, so the
    // reward is carried on a Not(OptionalEffectPerformed)-gated sub_ability
    // (the decline branch), NOT a top-level else_ability.
    let sub = def.sub_ability.as_ref().expect("should have sub_ability");
    assert_eq!(
        sub.condition,
        Some(AbilityCondition::Not {
            condition: Box::new(AbilityCondition::effect_performed())
        }),
        "reward sub must be gated Not(OptionalEffectPerformed), got {:?}",
        sub.condition
    );
    assert!(
        matches!(*sub.effect, Effect::Draw { .. }),
        "reward sub effect should be Draw, got {:?}",
        sub.effect
    );
    assert!(
        !matches!(*sub.effect, Effect::Unimplemented { .. }),
        "reward must not be Unimplemented"
    );
}

/// CR 608.2e + CR 109.5: Braids, Arisen Nightmare's decline-consequence
/// tail. "If you do, each opponent may sacrifice ... For each opponent who
/// doesn't, that player loses 2 life and you draw a card." must lower to a
/// `Sacrifice(opponent)` node (`IfYouDo`, `player_scope: Opponent`) whose
/// `Not{IfYouDo}`-conditioned body is `LoseLife { target: ScopedPlayer } →
/// Draw { target: OriginalController }`, both `ContinuationStep` links.
#[test]
fn for_each_opponent_who_doesnt_lowers_decline_consequence() {
    use crate::types::ability::SubAbilityLink;
    let def = parse_effect_chain(
        "you may sacrifice an artifact, creature, enchantment, land, or \
             planeswalker. If you do, each opponent may sacrifice a permanent \
             of their choice that shares a card type with it. For each \
             opponent who doesn't, that player loses 2 life and you draw a card.",
        AbilityKind::Spell,
    );
    // Root: the controller's optional sacrifice.
    assert!(matches!(*def.effect, Effect::Sacrifice { .. }));
    let sac_opponent = def
        .sub_ability
        .as_ref()
        .expect("controller sacrifice chains to the each-opponent sacrifice");
    assert!(matches!(*sac_opponent.effect, Effect::Sacrifice { .. }));
    assert_eq!(
        sac_opponent.condition,
        Some(AbilityCondition::effect_performed())
    );
    assert_eq!(
        sac_opponent.player_scope,
        Some(PlayerFilter::Opponent),
        "the each-opponent sacrifice iterates per opponent"
    );

    // Decline body head: LoseLife, gated on Not{IfYouDo}, ContinuationStep.
    let lose_life = sac_opponent
        .sub_ability
        .as_ref()
        .expect("the each-opponent sacrifice chains to the decline body");
    assert_eq!(
        lose_life.condition,
        Some(AbilityCondition::Not {
            condition: Box::new(AbilityCondition::effect_performed())
        }),
        "the decline body runs only for an opponent who did NOT sacrifice"
    );
    assert_eq!(lose_life.sub_link, SubAbilityLink::ContinuationStep);
    assert_eq!(
        lose_life.player_scope, None,
        "the body inherits player_scope from the parent — it does not set its own"
    );
    match &*lose_life.effect {
        Effect::LoseLife { target, .. } => assert_eq!(
            target.as_ref(),
            Some(&TargetFilter::ScopedPlayer),
            "\"that player\" is the scoped declining opponent"
        ),
        other => panic!("expected LoseLife, got {other:?}"),
    }

    // Decline body tail: Draw → the printed controller.
    let draw = lose_life
        .sub_ability
        .as_ref()
        .expect("the life loss chains to the draw");
    assert_eq!(draw.sub_link, SubAbilityLink::ContinuationStep);
    match &*draw.effect {
        Effect::Draw { target, .. } => assert_eq!(
            target,
            &TargetFilter::OriginalController,
            "\"you draw a card\" is Braids' printed controller"
        ),
        other => panic!("expected Draw, got {other:?}"),
    }
}

/// CR 118.12 + CR 608.2d + CR 109.5: Wernog, Rider's Chaplain — subject-only
/// OPTIONAL-decline tail. "each opponent may investigate. Each opponent who
/// doesn't loses 1 life. You investigate." must lower clause 2 as a
/// `Not{effect_performed()}`-gated `ContinuationStep` sub-ability of the
/// optional `Effect::Investigate` (player_scope: Opponent), NOT as the
/// previous unconditional `SequentialSibling`. The body's life-loss recipient
/// is rebound `Controller → ScopedPlayer` by
/// `rebind_subject_only_body_recipient`.
#[test]
fn wernog_subject_only_who_doesnt_lowers_optional_decline_gate() {
    use crate::types::ability::SubAbilityLink;
    let def = parse_effect_chain(
        "each opponent may investigate. Each opponent who doesn't loses 1 life. \
             You investigate.",
        AbilityKind::Spell,
    );
    // Root: each opponent's OPTIONAL investigate — player_scope: Opponent.
    assert!(matches!(*def.effect, Effect::Investigate));
    assert_eq!(
        def.player_scope,
        Some(PlayerFilter::Opponent),
        "the optional investigate iterates per opponent"
    );
    assert!(
        def.optional,
        "\"each opponent may investigate\" is optional"
    );

    // Clause 2 sub-ability: LoseLife, gated on Not{IfYouDo}, ContinuationStep.
    let lose_life = def
        .sub_ability
        .as_ref()
        .expect("the optional investigate chains to the decline body");
    assert_eq!(
        lose_life.condition,
        Some(AbilityCondition::Not {
            condition: Box::new(AbilityCondition::effect_performed())
        }),
        "the decline body runs only for an opponent who did NOT investigate"
    );
    assert_eq!(
        lose_life.sub_link,
        SubAbilityLink::ContinuationStep,
        "must be a within-action ContinuationStep, NOT the old unconditional \
             SequentialSibling"
    );
    assert_eq!(
        lose_life.player_scope, None,
        "the body inherits player_scope from the parent — it does not set its own"
    );
    match &*lose_life.effect {
        Effect::LoseLife { amount, target } => {
            assert_eq!(*amount, QuantityExpr::Fixed { value: 1 });
            assert_eq!(
                target.as_ref(),
                Some(&TargetFilter::ScopedPlayer),
                "the declining opponent loses the life (rebound Controller → ScopedPlayer)"
            );
        }
        other => panic!("expected LoseLife, got {other:?}"),
    }
}

/// CR 118.12 + CR 508.1c + CR 109.5: The Second Doctor — subject-only
/// OPTIONAL-ACCEPT consequence with a CROSS-SCOPE AddRestriction body.
/// "each player may draw a card. Each opponent who does can't attack you or
/// permanents you control during their next turn." must lower clause 2 as an
/// `And{[effect_performed(), ScopedPlayerMatches{Opponent}]}`-gated
/// `ContinuationStep` sub-ability of the optional `Effect::Draw`
/// (player_scope: All). The restriction's affected player is rebound
/// ParentTargetedPlayer → ScopedPlayer, the defended scope is the
/// "you or permanents you control" `PlayerOrPermanents`, and the pre-armed
/// `UntilEndOfNextTurnOf` duration survives lowering into the gated sub.
#[test]
fn second_doctor_subject_only_who_does_lowers_cross_scope_restriction() {
    use crate::types::ability::SubAbilityLink;
    use crate::types::triggers::AttackTargetFilter;
    let def = parse_effect_chain(
        "each player may draw a card. Each opponent who does can't attack you \
             or permanents you control during their next turn.",
        AbilityKind::Spell,
    );
    // Root: each player's OPTIONAL draw — player_scope: All.
    assert!(matches!(*def.effect, Effect::Draw { .. }));
    assert_eq!(
        def.player_scope,
        Some(PlayerFilter::All),
        "the optional draw iterates per player"
    );
    assert!(def.optional, "\"each player may draw a card\" is optional");

    let restriction = def
        .sub_ability
        .as_ref()
        .expect("the optional draw chains to the who-does consequence body");
    // CROSS-SCOPE gate: accept signal AND scoped player is an Opponent.
    assert_eq!(
        restriction.condition,
        Some(AbilityCondition::And {
            conditions: vec![
                AbilityCondition::effect_performed(),
                AbilityCondition::ScopedPlayerMatches {
                    filter: PlayerFilter::Opponent
                },
            ],
        }),
        "the body runs only for an OPPONENT who DID draw — controller never self-restricts"
    );
    assert_eq!(
        restriction.sub_link,
        SubAbilityLink::ContinuationStep,
        "must be a within-action ContinuationStep, not a SequentialSibling"
    );
    assert_eq!(
        restriction.player_scope, None,
        "the body inherits player_scope from the parent — it does not set its own"
    );
    // The expiry correctness hinges on this duration surviving lowering.
    assert_eq!(
        restriction.duration,
        Some(Duration::UntilEndOfNextTurnOf {
            player: crate::types::ability::PlayerScope::Controller
        }),
        "pre-armed end-of-next-turn anchor must survive into the gated sub"
    );
    match &*restriction.effect {
        Effect::AddRestriction {
            restriction:
                GameRestriction::ProhibitActivity {
                    affected_players,
                    activity,
                    ..
                },
        } => {
            assert_eq!(
                    *affected_players,
                    RestrictionPlayerScope::ScopedPlayer,
                    "the per-iteration opponent is restricted (rebound ParentTargetedPlayer → ScopedPlayer)"
                );
            assert_eq!(
                *activity,
                ProhibitedActivity::Attack {
                    defended: AttackTargetFilter::PlayerOrPermanents
                },
                "\"you or permanents you control\" defends player + permanents"
            );
        }
        other => panic!("expected AddRestriction, got {other:?}"),
    }
}

/// CR 118.12 + CR 508.1c + CR 109.5: City Hall — STRENGTHENING the restriction
/// path with a SAME-SCOPE (All), player-only defended scope. Proves the
/// building block generalizes across (a) defended scope ("you" → `Player` vs
/// The Second Doctor's `PlayerOrPermanents`) and (b) consequence filter (All vs
/// Opponent), i.e. "build for the class, not the card".
#[test]
fn city_hall_subject_only_who_does_lowers_same_scope_restriction() {
    use crate::types::ability::SubAbilityLink;
    use crate::types::triggers::AttackTargetFilter;
    let def = parse_effect_chain(
        "each player may create two tapped Treasure tokens. Each player who \
             does can't attack you during their next turn.",
        AbilityKind::Spell,
    );
    assert_eq!(
        def.player_scope,
        Some(PlayerFilter::All),
        "the optional token creation iterates per player"
    );
    assert!(def.optional, "\"each player may create\" is optional");

    let restriction = def
        .sub_ability
        .as_ref()
        .expect("the optional token creation chains to the who-does consequence");
    assert_eq!(
        restriction.condition,
        Some(AbilityCondition::And {
            conditions: vec![
                AbilityCondition::effect_performed(),
                AbilityCondition::ScopedPlayerMatches {
                    filter: PlayerFilter::All
                },
            ],
        }),
        "same-scope: the ScopedPlayerMatches{{All}} conjunct is a trivial no-op"
    );
    assert_eq!(restriction.sub_link, SubAbilityLink::ContinuationStep);
    match &*restriction.effect {
        Effect::AddRestriction {
            restriction:
                GameRestriction::ProhibitActivity {
                    affected_players,
                    activity,
                    ..
                },
        } => {
            assert_eq!(*affected_players, RestrictionPlayerScope::ScopedPlayer);
            assert_eq!(
                *activity,
                ProhibitedActivity::Attack {
                    defended: AttackTargetFilter::Player
                },
                "bare \"you\" defends the player only"
            );
        }
        other => panic!("expected AddRestriction, got {other:?}"),
    }
}

/// CR 118.12 + CR 109.5: Step Between Worlds — generalization across a
/// NON-restriction effect. "Each player may shuffle their hand and graveyard
/// into their library. Each player who does draws seven cards." must lower
/// clause 2 as an `effect_performed()`-gated `Draw` whose recipient is rebound
/// Controller → ScopedPlayer, proving the SubjectOnly recipient rebind carries
/// the consequence to the scoped player beyond the AddRestriction cards.
#[test]
fn step_between_worlds_subject_only_who_does_lowers_draw() {
    use crate::types::ability::SubAbilityLink;
    let def = parse_effect_chain(
        "Each player may shuffle their hand and graveyard into their library. \
             Each player who does draws seven cards.",
        AbilityKind::Spell,
    );
    assert_eq!(
        def.player_scope,
        Some(PlayerFilter::All),
        "the optional shuffle iterates per player"
    );
    assert!(def.optional, "\"each player may shuffle\" is optional");

    // The compound shuffle parent ("shuffle their hand and graveyard into
    // their library") lowers into a 3-step chain (ChangeZoneAll Hand→Library,
    // ChangeZoneAll Graveyard→Library, Shuffle); the who-does Draw consequence
    // is the leaf sub-ability. Walk to the Draw node.
    let mut node = def
        .sub_ability
        .as_deref()
        .expect("the optional shuffle chains onward");
    while !matches!(*node.effect, Effect::Draw { .. }) {
        node = node
            .sub_ability
            .as_deref()
            .expect("the chain reaches the who-does Draw consequence");
    }
    let draw = node;
    assert_eq!(
        draw.condition,
        Some(AbilityCondition::And {
            conditions: vec![
                AbilityCondition::effect_performed(),
                AbilityCondition::ScopedPlayerMatches {
                    filter: PlayerFilter::All
                },
            ],
        }),
        "the draw runs only for a player who DID shuffle"
    );
    assert_eq!(draw.sub_link, SubAbilityLink::ContinuationStep);
    match &*draw.effect {
        Effect::Draw { count, target } => {
            assert_eq!(*count, QuantityExpr::Fixed { value: 7 });
            assert_eq!(
                target,
                &TargetFilter::ScopedPlayer,
                "the shuffling player draws (rebound Controller → ScopedPlayer)"
            );
        }
        other => panic!("expected Draw, got {other:?}"),
    }
}

/// CR 109.4 + CR 109.5: Thornbow no-regression invariant. "each opponent who
/// doesn't control an Elf loses 1 life" is a STATIC-BOARD shape consumed by
/// `strip_controls_permanent_clause` (→ `ControlsCount`), NOT a decline gate.
/// The new `who doesn't` guard/dispatcher must NOT intercept it: the clause
/// must carry `condition: None` (no decline gate) and a `ControlsCount`-scoped
/// player_scope. Locks the ordering invariant — `strip_controls_permanent_clause`
/// runs BEFORE the `who doesn't` guard.
#[test]
fn each_opponent_who_doesnt_control_type_is_controls_count_not_decline_gate() {
    let def = parse_effect_chain(
        "each opponent who doesn't control an Elf loses 1 life",
        AbilityKind::Spell,
    );
    assert!(
        matches!(*def.effect, Effect::LoseLife { .. }),
        "expected a LoseLife effect, got {:?}",
        def.effect
    );
    assert_eq!(
        def.condition, None,
        "a controls-count board filter is NOT a decline gate — condition must be None"
    );
    assert!(
        matches!(def.player_scope, Some(PlayerFilter::ControlsCount { .. })),
        "expected a ControlsCount-scoped subject, got {:?}",
        def.player_scope
    );
}

/// CR 101.3 + CR 608.2c + CR 118.12: Refurbished Familiar / Aclazotz,
/// Deepest Betrayal — mandatory-impossible decline-tail. "each opponent
/// discards a card. For each opponent who can't, you draw a card." must
/// lower to a `Discard(opponent)` node (`player_scope: Opponent`) whose
/// `Not{IfCurrentScopeSucceeded}`-conditioned body is
/// `Draw { target: OriginalController }`, a `ContinuationStep` link.
/// Asserted alongside the unchanged `Not{IfYouDo}` shape for the
/// `doesn't` arm to guard against the new arm cross-contaminating.
#[test]
fn for_each_opponent_who_cant_lowers_to_if_current_scope_succeeded() {
    use crate::types::ability::SubAbilityLink;
    let def = parse_effect_chain(
        "each opponent discards a card. For each opponent who can't, you draw a card.",
        AbilityKind::Spell,
    );
    // Root: each opponent discards — player_scope: Opponent.
    assert!(matches!(*def.effect, Effect::Discard { .. }));
    assert_eq!(
        def.player_scope,
        Some(PlayerFilter::Opponent),
        "the discard iterates per opponent"
    );
    // Decline body: Draw, gated on Not{IfCurrentScopeSucceeded}.
    let draw = def
        .sub_ability
        .as_ref()
        .expect("discard chains to the decline body");
    assert_eq!(
        draw.condition,
        Some(AbilityCondition::Not {
            condition: Box::new(AbilityCondition::current_scope_succeeded())
        }),
        "the can't body runs only for an opponent whose mandatory discard failed"
    );
    assert_eq!(draw.sub_link, SubAbilityLink::ContinuationStep);
    match &*draw.effect {
        Effect::Draw { target, .. } => assert_eq!(
            target,
            &TargetFilter::OriginalController,
            "\"you draw a card\" is the printed controller"
        ),
        other => panic!("expected Draw, got {other:?}"),
    }

    // Regression guard: the "doesn't" arm must still stamp Not{IfYouDo},
    // NOT the new IfCurrentScopeSucceeded variant. Use a Braids-shaped
    // optional parent so the doesn't arm is reachable.
    let braids_like = parse_effect_chain(
        "each opponent may sacrifice a creature of their choice. For each \
             opponent who doesn't, you draw a card.",
        AbilityKind::Spell,
    );
    let braids_draw = braids_like
        .sub_ability
        .as_ref()
        .expect("optional sacrifice chains to the decline body");
    assert_eq!(
        braids_draw.condition,
        Some(AbilityCondition::Not {
            condition: Box::new(AbilityCondition::effect_performed())
        }),
        "the doesn't arm must still stamp Not{{IfYouDo}} (optional-decline branch)"
    );
}

#[test]
fn for_each_opponent_who_cant_is_case_insensitive() {
    use crate::types::ability::SubAbilityLink;

    let def = parse_effect_chain(
        "Each opponent discards a card. For each opponent who can't, you draw a card.",
        AbilityKind::Spell,
    );

    assert!(matches!(*def.effect, Effect::Discard { .. }));
    assert_eq!(def.player_scope, Some(PlayerFilter::Opponent));

    let draw = def
        .sub_ability
        .as_ref()
        .expect("discard should chain to the can't consequence");
    assert_eq!(
        draw.player_scope, None,
        "the body inherits the surrounding opponent scope instead of starting a second loop"
    );
    assert_eq!(draw.sub_link, SubAbilityLink::ContinuationStep);
    assert_eq!(
        draw.condition,
        Some(AbilityCondition::Not {
            condition: Box::new(AbilityCondition::current_scope_succeeded())
        })
    );
    match &*draw.effect {
        Effect::Draw { target, .. } => assert_eq!(
            target,
            &TargetFilter::OriginalController,
            "\"you draw\" remains the printed controller inside the per-opponent loop"
        ),
        other => panic!("expected Draw, got {other:?}"),
    }
}

