#[test]
fn parent_controller_may_sacrifice_if_player_does_gates_copy() {
    let def = parse_effect_chain(
            "return target nonland permanent to its owner's hand. Then that permanent's controller may sacrifice a land of their choice. If the player does, they may copy this spell and may choose a new target for that copy",
            AbilityKind::Spell,
        );
    let sacrifice = def
        .sub_ability
        .as_ref()
        .expect("bounce should chain to optional sacrifice");
    assert!(sacrifice.optional);
    match &*sacrifice.effect {
        Effect::Sacrifice {
            target: TargetFilter::Typed(tf),
            ..
        } => {
            assert!(tf.type_filters.contains(&TypeFilter::Land));
            assert_eq!(tf.controller, Some(ControllerRef::ParentTargetController));
        }
        other => panic!("expected Sacrifice land, got {other:?}"),
    }
    let copy = sacrifice
        .sub_ability
        .as_ref()
        .expect("sacrifice should chain to copy spell");
    assert_eq!(copy.condition, Some(AbilityCondition::effect_performed()));
    assert!(matches!(*copy.effect, Effect::CopySpell { .. }));
}

/// CR 608.2d + CR 603.2: "each opponent may X" — each opponent independently
/// decides yes/no. Lowered to `optional: true` + `player_scope: Opponent`
/// (not `OpponentMayScope::AnyOpponent`, which is first-accept-wins).
/// At runtime the outer player_scope iteration rebinds controller per
/// opponent, and each scoped clone enters OptionalEffectChoice for that
/// opponent. Source: Fandaniel, Telophoroi Ascian Oracle.
#[test]
fn each_opponent_may_sets_optional_with_opponent_scope() {
    let def = parse_effect_chain(
        "each opponent may sacrifice a nontoken creature of their choice",
        AbilityKind::Spell,
    );
    assert!(def.optional, "expected optional=true, got {def:?}");
    assert_eq!(
        def.optional_for, None,
        "each-opponent-may must NOT set optional_for (which is AnyOpponent-only)"
    );
    assert_eq!(
        def.player_scope,
        Some(PlayerFilter::Opponent),
        "expected player_scope=Opponent, got {:?}",
        def.player_scope
    );
    assert!(
        matches!(*def.effect, Effect::Sacrifice { .. }),
        "effect should be Sacrifice, got {:?}",
        def.effect
    );
}

