/// CR 400.7 + CR 608.2c + CR 701.20b — Bloodline Shaman class
/// ("Reveal the top card of your library. If <cond>, put it into your hand.
/// Otherwise, put it into your graveyard."): the destination word
/// "graveyard" must NOT be misread as a graveyard ORIGIN. After the
/// destination-needle strip, both branches parse with `origin: None` (the
/// revealed card is moved from the library via the injected reveal target,
/// not scanned out of a "from <zone>" origin). Before the fix the else
/// branch produced `origin: Some(Zone::Graveyard)`, which tripped the
/// resolver's origin-mismatch guard and made the move a runtime no-op.
#[test]
fn reveal_otherwise_graveyard_branch_has_no_origin() {
    let def = parse_effect_chain(
            "Reveal the top card of your library. If that card is a creature card of the chosen type, put it into your hand. Otherwise, put it into your graveyard.",
            crate::types::ability::AbilityKind::Activated,
        );
    assert!(
        matches!(*def.effect, Effect::RevealTop { .. }),
        "primary effect should be RevealTop, got {:?}",
        def.effect
    );
    let sub = def
        .sub_ability
        .as_deref()
        .expect("reveal should carry a conditional sub_ability for the hand branch");
    // The hand branch (positive). After the destination-needle strip, "into
    // your hand" carries no origin keyword -> origin: None.
    match &*sub.effect {
        Effect::ChangeZone {
            origin,
            destination,
            ..
        } => {
            assert_eq!(*destination, Zone::Hand);
            assert_eq!(
                *origin, None,
                "hand branch ChangeZone must have origin: None"
            );
        }
        other => panic!("expected hand-branch ChangeZone, got {other:?}"),
    }
    // The Otherwise branch (the previously-broken path). "into your
    // graveyard" must ALSO yield origin: None — not Some(Graveyard).
    let else_ab = sub
        .else_ability
        .as_deref()
        .expect("reveal/otherwise should carry an else_ability for the graveyard branch");
    match &*else_ab.effect {
        Effect::ChangeZone {
            origin,
            destination,
            ..
        } => {
            assert_eq!(*destination, Zone::Graveyard);
            assert_eq!(
                *origin, None,
                "graveyard branch ChangeZone must have origin: None, not Some(Zone::Graveyard)"
            );
        }
        other => panic!("expected graveyard-branch ChangeZone, got {other:?}"),
    }
}

#[test]
fn copy_token_suffix_condition_attaches_otherwise() {
    let (suffix_cond, suffix_text) = strip_suffix_conditional(
            "create a tapped token that's a copy of ~ if seven or more land cards are in your graveyard",
            &mut ParseContext::default(),
        );
    let condition_probe = try_nom_condition_as_ability_condition(
        "seven or more land cards are in your graveyard",
        &mut ParseContext::default(),
    );
    assert!(
        condition_probe.is_some(),
        "condition bridge should parse subject-first zone count"
    );
    assert!(
        suffix_cond.is_some(),
        "suffix stripper should parse condition"
    );
    assert_eq!(suffix_text, "create a tapped token that's a copy of ~");

    let chain = parse_effect_chain(
            "create a tapped token that's a copy of this creature if seven or more land cards are in your graveyard. Otherwise, create a tapped 1/1 black Insect creature token with flying.",
            crate::types::ability::AbilityKind::Spell,
        );
    assert!(
        matches!(
            &*chain.effect,
            Effect::CopyTokenOf {
                tapped: true,
                enters_attacking: false,
                ..
            }
        ),
        "expected tapped CopyTokenOf, got {:?}",
        chain.effect
    );
    assert!(
        matches!(
            chain.condition,
            Some(AbilityCondition::QuantityCheck {
                lhs: QuantityExpr::Ref {
                    qty: QuantityRef::ZoneCardCount {
                        zone: ZoneRef::Graveyard,
                        ref card_types,
                        scope: CountScope::Controller,
                        filter: None,
                    }
                },
                comparator: Comparator::GE,
                rhs: QuantityExpr::Fixed { value: 7 },
            }) if card_types == &vec![TypeFilter::Land]
        ),
        "expected land graveyard condition, got {:?}",
        chain.condition
    );
    let else_ab = chain
        .else_ability
        .as_ref()
        .expect("CopyTokenOf should carry Otherwise else_ability");
    assert!(
        matches!(
            &*else_ab.effect,
            Effect::Token {
                name,
                tapped: true,
                keywords,
                ..
            } if name == "Insect" && keywords.contains(&Keyword::Flying)
        ),
        "expected tapped flying Insect fallback, got {:?}",
        else_ab.effect
    );
}

#[test]
fn creature_card_of_the_chosen_type_conditional() {
    // Herald's Horn pattern: "look at top, if it's a creature card of the chosen type,
    // you may reveal it and put it into your hand."
    let chain = parse_effect_chain(
            "look at the top card of your library. If it's a creature card of the chosen type, you may reveal it and put it into your hand.",
            crate::types::ability::AbilityKind::Spell,
        );
    // First effect: Dig (look at top 1, private)
    assert!(
        matches!(*chain.effect, Effect::Dig { .. }),
        "expected Dig, got: {:?}",
        chain.effect
    );
    // Sub-ability chain should have the conditional
    let sub = chain
        .sub_ability
        .as_ref()
        .expect("should have sub_ability after Dig");
    assert_eq!(
        sub.condition,
        Some(AbilityCondition::RevealedHasCardType {
            card_types: vec![CoreType::Creature],
            additional_filter: Some(FilterProp::IsChosenCreatureType),
            subtype_filter: None,
        }),
        "condition should check creature type + chosen type"
    );
    // The sub-ability should be optional ("you may")
    assert!(sub.optional, "should be optional (you may)");
    // Walk the sub-ability chain to find ChangeZone to Hand
    let mut found_change_zone = false;
    let mut current = Some(sub.as_ref());
    while let Some(def) = current {
        if matches!(
            &*def.effect,
            Effect::ChangeZone {
                destination: Zone::Hand,
                ..
            }
        ) {
            found_change_zone = true;
            break;
        }
        current = def.sub_ability.as_deref();
    }
    assert!(
        found_change_zone,
        "should have ChangeZone to Hand in sub-ability chain"
    );
}

#[test]
fn scroll_rack_activated_effect_chain() {
    let chain = parse_effect_chain(
            "Exile any number of cards from your hand face down. Put that many cards from the top of your library into your hand. Then look at the exiled cards and put them on top of your library in any order.",
            AbilityKind::Activated,
        );
    let mut current = Some(&chain);
    let mut effects = Vec::new();
    while let Some(def) = current {
        effects.push(def.effect.as_ref().clone());
        current = def.sub_ability.as_deref();
    }
    assert!(
        effects.iter().any(|e| {
            matches!(
                e,
                Effect::Mill {
                    count: QuantityExpr::Ref {
                        qty: QuantityRef::CardsExiledBySource,
                    },
                    destination: Zone::Hand,
                    ..
                }
            )
        }),
        "expected top-library move to hand tied to CardsExiledBySource, got {effects:?}"
    );
    assert!(
        !effects.iter().any(|e| matches!(e, Effect::Draw { .. })),
        "CR 121.5: Scroll Rack puts cards into hand without drawing them"
    );
    assert!(
        effects.iter().any(|e| {
            matches!(
                e,
                Effect::PutAtLibraryPosition {
                    target: TargetFilter::ExiledBySource,
                    ..
                }
            )
        }),
        "expected exiled cards put on library top, got {effects:?}"
    );
    assert!(
        effects.iter().any(|e| {
            matches!(
                e,
                Effect::RevealHand {
                    target: TargetFilter::ExiledBySource,
                    ..
                }
            )
        }),
        "expected private look at exiled cards, got {effects:?}"
    );
    assert!(
        !effects
            .iter()
            .any(|e| matches!(e, Effect::Unimplemented { .. })),
        "chain must not contain Unimplemented effects"
    );
}

