#[test]
fn combat_class_pump_all_for_each_other_than_source_is_dynamic() {
    // CR 611.2c: Márton Stromgald's resolving triggered ability creates a
    // continuous effect whose affected set and P/T amount are both combat
    // class counts excluding the source object.
    let clause = parse_effect_clause(
            "other attacking creatures get +1/+1 until end of turn for each attacking creature other than ~.",
            &mut ParseContext::default(),
        );
    match &clause.effect {
        Effect::PumpAll {
            target,
            power,
            toughness,
        } => {
            assert_eq!(clause.duration, Some(Duration::UntilEndOfTurn));
            assert!(matches!(
                target,
                TargetFilter::Typed(TypedFilter {
                    type_filters,
                    properties,
                    ..
                }) if type_filters.contains(&TypeFilter::Creature)
                    && properties.contains(&FilterProp::Attacking { defender: None })
                    && properties.contains(&FilterProp::Another)
            ));
            assert!(matches!(
                power,
                PtValue::Quantity(QuantityExpr::Ref {
                    qty: QuantityRef::ObjectCount {
                        filter: TargetFilter::Typed(TypedFilter {
                            type_filters,
                            properties,
                            ..
                        })
                    }
                }) if type_filters == &vec![TypeFilter::Creature]
                    && properties == &vec![FilterProp::Attacking { defender: None }, FilterProp::Another]
            ));
            assert_eq!(power, toughness);
        }
        other => panic!("expected PumpAll, got: {other:?}"),
    }

    let clause = parse_effect_clause(
            "other blocking creatures get +1/+1 until end of turn for each blocking creature other than ~.",
            &mut ParseContext::default(),
        );
    assert!(matches!(
        clause.effect,
        Effect::PumpAll {
            power: PtValue::Quantity(QuantityExpr::Ref {
                qty: QuantityRef::ObjectCount {
                    filter: TargetFilter::Typed(TypedFilter {
                        type_filters,
                        properties,
                        ..
                    })
                }
            }),
            ..
        } if type_filters == vec![TypeFilter::Creature]
            && properties == vec![FilterProp::Blocking, FilterProp::Another]
    ));
}

#[test]
fn perpetual_parser_maps_self_base_pt() {
    use crate::types::ability::PerpetualModification;
    // Self-subject base-P/T form (High Fae Prankster); the card's own name
    // normalizes to `~` in Oracle text.
    let e = parse_effect("~ perpetually has base power and toughness 4/1.");
    assert!(matches!(
        e,
        Effect::ApplyPerpetual {
            modification: PerpetualModification::SetBasePowerToughness {
                power: 4,
                toughness: 1,
            },
            ..
        }
    ));

    // "become(s)" verb variant. (Uses an unambiguous self-subject; the
    // anaphoric "it" form is intentionally not accepted.)
    let e = parse_effect("This creature perpetually becomes base power and toughness 2/2.");
    assert!(matches!(
        e,
        Effect::ApplyPerpetual {
            modification: PerpetualModification::SetBasePowerToughness {
                power: 2,
                toughness: 2,
            },
            ..
        }
    ));
}

#[test]
fn perpetual_parser_maps_modify_pt() {
    use crate::types::ability::PerpetualModification;
    let e = parse_effect("~ perpetually gets +3/+3.");
    assert!(matches!(
        e,
        Effect::ApplyPerpetual {
            modification: PerpetualModification::ModifyPowerToughness {
                power_delta: 3,
                toughness_delta: 3,
            },
            ..
        }
    ));

    let e = parse_effect("that vehicle perpetually gets +1/+0.");
    assert!(matches!(
        e,
        Effect::ApplyPerpetual {
            target: TargetFilter::ParentTarget,
            modification: PerpetualModification::ModifyPowerToughness {
                power_delta: 1,
                toughness_delta: 0,
            },
            ..
        }
    ));
}

