/// CR 118.9 + CR 119.4: Nashi's "If you cast a spell this way, pay life
/// equal to its mana value rather than paying its mana cost" must fold
/// onto the previous `CastFromZone` clause as `alt_ability_cost`, NOT
/// emit as a sibling `Unimplemented{name:"pay"}`. Building-block test:
/// exercises both `try_parse_alt_cost_rider` (rider recognition) and
/// `attach_alt_cost_to_prior_cast_from_zone` (chain folding).
#[test]
fn alt_cost_rider_folds_onto_prior_cast_from_zone() {
    let def = super::parse_effect_chain(
            "exile the top card of each player's library. Until end of turn, you may play one of those cards. If you cast a spell this way, pay life equal to its mana value rather than paying its mana cost.",
            AbilityKind::Spell,
        );
    assert_eq!(def.player_scope, Some(PlayerFilter::All));
    assert!(
        matches!(
            def.effect.as_ref(),
            Effect::ExileTop {
                player: TargetFilter::Controller,
                count: QuantityExpr::Fixed { value: 1 },
                face_down: false,
            }
        ),
        "expected all-player ExileTop to use player_scope + Controller, got {:?}",
        def.effect
    );
    // Walk the chain looking for the CastFromZone with alt_ability_cost set.
    fn find_cast(d: &AbilityDefinition) -> Option<&Effect> {
        if matches!(*d.effect, Effect::CastFromZone { .. }) {
            return Some(&d.effect);
        }
        d.sub_ability.as_ref().and_then(|s| find_cast(s))
    }
    let cast = find_cast(&def).expect("CastFromZone should be in chain");
    let Effect::CastFromZone {
        alt_ability_cost: Some(alt),
        ..
    } = cast
    else {
        panic!("expected CastFromZone with alt_ability_cost, got {cast:?}");
    };
    assert!(
        matches!(
            alt,
            crate::types::ability::AbilityCost::PayLife {
                amount: crate::types::ability::QuantityExpr::Ref {
                    qty: crate::types::ability::QuantityRef::SelfManaValue,
                },
            }
        ),
        "expected PayLife {{ SelfManaValue }}, got {alt:?}",
    );
    // Verify the rider didn't leak a sibling Unimplemented{name:"pay"} effect.
    fn has_pay_unimpl(d: &AbilityDefinition) -> bool {
        if matches!(
            &*d.effect,
            Effect::Unimplemented { name, .. } if name == "pay"
        ) {
            return true;
        }
        d.sub_ability.as_ref().is_some_and(|s| has_pay_unimpl(s))
    }
    assert!(
        !has_pay_unimpl(&def),
        "rider must NOT leak as Unimplemented{{name:'pay'}} sibling"
    );
}

#[test]
fn reflexive_damage_any_target_keeps_explicit_target() {
    let def = super::parse_effect_chain(
            "Sacrifice a creature. When you do, Minsc & Boo deals X damage to any target, where X is that creature's power. If the sacrificed creature was a Hamster, draw X cards.",
            AbilityKind::Spell,
        );
    assert!(matches!(&*def.effect, Effect::Sacrifice { .. }));

    let damage = def.sub_ability.as_ref().expect("damage sub-ability");
    assert_eq!(damage.condition, Some(AbilityCondition::WhenYouDo));
    let Effect::DealDamage {
        amount:
            QuantityExpr::Ref {
                qty:
                    QuantityRef::Power {
                        scope: ObjectScope::CostPaidObject,
                    },
            },
        target: TargetFilter::Any,
        ..
    } = damage.effect.as_ref()
    else {
        panic!(
            "expected reflexive damage to keep Any target and cost-paid power, got {:?}",
            damage.effect
        );
    };

    let draw = damage
        .sub_ability
        .as_ref()
        .expect("Hamster draw sub-ability");
    assert!(matches!(
        &*draw.effect,
        Effect::Draw {
            count: QuantityExpr::Ref {
                qty: QuantityRef::Power {
                    scope: ObjectScope::CostPaidObject
                }
            },
            ..
        }
    ));
    assert!(matches!(
        draw.condition,
        Some(AbilityCondition::CostPaidObjectMatchesFilter {
            filter: TargetFilter::Typed(TypedFilter { ref type_filters, .. })
        }) if type_filters.iter().any(|filter| {
            matches!(filter, TypeFilter::Subtype(subtype) if subtype == "Hamster")
        })
    ));
}

/// CR 509.1b + CR 611.2c: Martha Jones's conjoined-subject evasion grant
/// "<source> and up to one other target creature can't be blocked this turn"
/// lowers to two `CantBeBlocked` grants — the source as the primary effect,
/// the targeted creature as a `multi_target {0, Fixed 1}` sub_ability. Builds
/// the class of "<self> and up to N other target creature(s)" evasion riders.
#[test]
fn source_and_other_cant_be_blocked_splits_into_two_grants() {
    use crate::types::ability::FilterProp;
    use crate::types::statics::StaticMode;
    let def = super::parse_effect_chain(
        "~ and up to one other target creature can't be blocked this turn",
        AbilityKind::Spell,
    );

    // Primary grant: the source (SelfRef), no target, UntilEndOfTurn.
    let Effect::GenericEffect {
        static_abilities,
        duration,
        target,
    } = def.effect.as_ref()
    else {
        panic!("expected primary GenericEffect, got {:?}", def.effect);
    };
    assert!(target.is_none());
    assert_eq!(*duration, Some(Duration::UntilEndOfTurn));
    assert_eq!(static_abilities.len(), 1);
    assert!(matches!(
        static_abilities[0].mode,
        StaticMode::CantBeBlocked
    ));
    assert!(matches!(
        static_abilities[0].affected,
        Some(TargetFilter::SelfRef)
    ));
    assert!(
        def.multi_target.is_none(),
        "primary grant takes no target slot"
    );

    // Secondary grant: up to one OTHER target creature, multi_target {0,1}.
    let other = def
        .sub_ability
        .as_ref()
        .expect("expected the targeted-creature grant as a sub_ability");
    let Effect::GenericEffect {
        static_abilities: sub_statics,
        duration: sub_duration,
        target: Some(sub_target),
    } = other.effect.as_ref()
    else {
        panic!(
            "expected secondary GenericEffect with target, got {:?}",
            other.effect
        );
    };
    // CR 611.2b: the sub_ability's UntilEndOfTurn is normalized to None and
    // re-applied at resolution by the GenericEffect resolver's default
    // (`ability.duration.or(inner).unwrap_or(UntilEndOfTurn)`), so either the
    // explicit duration or the normalized None is rules-correct here.
    assert!(matches!(
        (sub_duration, other.duration.as_ref()),
        (Some(Duration::UntilEndOfTurn), _) | (None, Some(Duration::UntilEndOfTurn)) | (None, None)
    ));
    assert!(matches!(sub_statics[0].mode, StaticMode::CantBeBlocked));
    assert!(matches!(
        sub_target,
        TargetFilter::Typed(TypedFilter { ref type_filters, ref properties, .. })
            if type_filters.iter().any(|f| matches!(f, TypeFilter::Creature))
                && properties.iter().any(|p| matches!(p, FilterProp::Another))
    ));
    assert_eq!(
        other.multi_target,
        Some(MultiTargetSpec::up_to(QuantityExpr::Fixed { value: 1 })),
    );
}

/// CR 603.12 + CR 701.21a + CR 701.26a: Nyssa of Traken's reflexive
/// "When you sacrifice one or more artifacts this way, tap up to that many
/// target creatures and draw that many cards" — the reflexive sacrifice gate
/// is consumed (→ `ZoneChangedThisWay { Artifact }`), the tap keeps its
/// `up_to(EventContextAmount)` count instead of discarding it, and the Draw
/// sibling is preserved.
#[test]
fn reflexive_sacrifice_this_way_taps_and_draws_that_many() {
    let def = super::parse_effect_chain(
            "When you sacrifice one or more artifacts this way, tap up to that many target creatures and draw that many cards",
            AbilityKind::Spell,
        );

    // Tap with a dynamic up-to count + the reflexive sacrifice condition.
    let Effect::SetTapState {
        scope: EffectScope::Single,
        state: TapStateChange::Tap,
        ..
    } = def.effect.as_ref()
    else {
        panic!("expected SetTapState Single/Tap, got {:?}", def.effect);
    };
    assert_eq!(
        def.multi_target,
        Some(MultiTargetSpec::up_to(QuantityExpr::Ref {
            qty: QuantityRef::EventContextAmount,
        })),
        "tap must surface up-to-that-many target slots",
    );
    assert!(matches!(
        def.condition,
        Some(AbilityCondition::ZoneChangedThisWay {
            filter: TargetFilter::Typed(TypedFilter { ref type_filters, .. })
        }) if type_filters.iter().any(|f| matches!(f, TypeFilter::Artifact))
    ));

    // Draw that many cards rides as the sibling.
    let draw = def.sub_ability.as_ref().expect("expected Draw sibling");
    assert!(matches!(
        &*draw.effect,
        Effect::Draw {
            count: QuantityExpr::Ref {
                qty: QuantityRef::EventContextAmount
            },
            ..
        }
    ));
}

