/// Sin, Spira's Punishment — full-card parse drops zero `Unimplemented` nodes
/// and the trigger's root carries the unbounded `WhileCondition` repeat.
#[test]
fn sin_spiras_punishment_parses_repeat_while_land() {
    use crate::types::ability::RepeatContinuation;
    let parsed = parse_oracle_text(
            "Flying\nWhenever Sin enters or attacks, exile a permanent card from your graveyard at random, then create a tapped token that's a copy of that card. If the exiled card is a land card, repeat this process.",
            "Sin, Spira's Punishment",
            &["Flying".to_string()],
            &["Creature".to_string()],
            &[],
        );
    let json = serde_json::to_string(&parsed).unwrap();
    assert!(
        // allow-noncombinator: test assertion scans serialized AST JSON, not parsing dispatch
        !json.contains("\"Unimplemented\""),
        "Sin must parse with zero Unimplemented nodes"
    );
    let trigger = parsed
        .triggers
        .iter()
        .find_map(|t| t.execute.as_ref())
        .expect("enters-or-attacks trigger with an execute body");
    assert!(
        matches!(
            trigger.repeat_until,
            Some(RepeatContinuation::WhileCondition {
                max_iterations: None,
                ..
            })
        ),
        "Sin's repeat is an unbounded WhileCondition, got {:?}",
        trigger.repeat_until
    );
}

/// Claim Jumper — full-card parse drops zero `Unimplemented` nodes and the
/// trigger's root carries the bounded ("once") `WhileCondition` repeat.
#[test]
fn claim_jumper_parses_repeat_once_while_opponent_lands() {
    use crate::types::ability::RepeatContinuation;
    let parsed = parse_oracle_text(
            "Vigilance\nWhen this creature enters, if an opponent controls more lands than you, you may search your library for a Plains card and put it onto the battlefield tapped. Then if an opponent controls more lands than you, repeat this process once. If you search your library this way, shuffle.",
            "Claim Jumper",
            &["Vigilance".to_string()],
            &["Creature".to_string()],
            &[],
        );
    let json = serde_json::to_string(&parsed).unwrap();
    assert!(
        // allow-noncombinator: test assertion scans serialized AST JSON, not parsing dispatch
        !json.contains("\"Unimplemented\""),
        "Claim Jumper must parse with zero Unimplemented nodes"
    );
    let trigger = parsed
        .triggers
        .iter()
        .find_map(|t| t.execute.as_ref())
        .expect("enters trigger with an execute body");
    assert!(
        matches!(
            trigger.repeat_until,
            Some(RepeatContinuation::WhileCondition {
                max_iterations: Some(1),
                ..
            })
        ),
        "Claim Jumper repeats once, got {:?}",
        trigger.repeat_until
    );
}

/// CR 608.2d: The choice-list splitter must treat a double-quoted granted
/// ability as one opaque item, so a `,`/`or` inside quoted text never
/// fabricates extra branches. A genuine unquoted disjunction still splits.
#[test]
fn split_choice_list_items_is_quote_aware() {
    // Quoted ability carrying an inner ", create …" is a single item.
    let nested = "a 3/3 blue Fish creature token with \"When this token dies, create a 6/6 blue Whale creature token.\"";
    assert_eq!(
        split_choice_list_items(nested),
        Some(vec![nested]),
        "a quoted ability with an inner comma must stay one item"
    );
    // A real top-level disjunction still splits into its branches.
    assert_eq!(
        split_choice_list_items("a Food token or a Treasure token"),
        Some(vec!["a Food token", "a Treasure token"]),
    );
    // A real split survives even when one branch carries a quoted ability
    // whose text contains a separator.
    assert_eq!(
        split_choice_list_items(
            "a Treasure token or a 1/1 Soldier with \"When this dies, draw a card.\""
        ),
        Some(vec![
            "a Treasure token",
            "a 1/1 Soldier with \"When this dies, draw a card.\""
        ]),
    );
}

/// CR 111.2 + CR 608.2d: Reef Worm creates a single cascading Fish token that
/// carries a quoted death-triggered ability; it is NOT a modal token choice.
/// Before the quote-aware splitter, the inner ", create …" severed the clause
/// into a bogus `ChooseOneOf` of Fish/Whale/Kraken. (issue #4230)
#[test]
fn reef_worm_nested_token_is_not_modal_choice() {
    let def = parse_effect_chain(
            "create a 3/3 blue Fish creature token with \"When this token dies, create a 6/6 blue Whale creature token with 'When this token dies, create a 9/9 blue Kraken creature token.'\"",
            AbilityKind::Spell,
        );
    let Effect::Token { name, .. } = &*def.effect else {
        panic!(
            "Reef Worm must create one Token (not a choice), got {:?}",
            def.effect
        );
    };
    assert_eq!(name, "Fish", "outer token is the 3/3 Fish");
}
